// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

interface EditorPageProps {
    user: User | null;
}

const EditorPage: React.FC<EditorPageProps> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY' | 'NONE'>('NONE');
    const [isSnapping, setIsSnapping] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Interactions refs
    const drawInteraction = useRef<Draw | null>(null);
    const modifyInteraction = useRef<Modify | null>(null);
    const snapInteraction = useRef<Snap | null>(null);
    const selectInteraction = useRef<Select | null>(null);

    const editStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
        stroke: new style.Stroke({ color: '#3b82f6', width: 3 }),
        image: new style.Circle({ radius: 7, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 2 }) })
    });

    const selectedStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.2)' }),
        stroke: new style.Stroke({ color: '#f97316', width: 4, lineDash: [5, 5] }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#f97316' }), stroke: new style.Stroke({ color: '#fff', width: 2 }) })
    });

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) {
            setVertices([]);
            return;
        }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            // Remove last point if it's the same as first
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const initMap = async () => {
        if (!mapElement.current) return;

        const tables = await gisService.getSpatialTables().catch(() => []);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);

        const maps = await gisService.getBasemaps().catch(() => []);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new VectorLayer({ source: editSource.current, style: editStyle, zIndex: 100 })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 15 }),
            controls: []
        });

        selectInteraction.current = new Select({ style: selectedStyle });
        map.addInteraction(selectInteraction.current);

        selectInteraction.current.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    // Handle Basemap changes
    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;

        const baseLayer = mapInstance.current.getLayers().getArray()[0] as TileLayer<any>;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else {
            const url = config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}');
            source = new XYZ({ url, crossOrigin: 'anonymous' });
        }
        baseLayer.setSource(source);
    }, [activeBasemapId, basemaps]);

    // Handle Interaction changes
    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;

        // Clean up
        if (drawInteraction.current) map.removeInteraction(drawInteraction.current);
        if (modifyInteraction.current) map.removeInteraction(modifyInteraction.current);
        if (snapInteraction.current) map.removeInteraction(snapInteraction.current);

        if (activeInteraction === 'DRAW') {
            drawInteraction.current = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(drawInteraction.current);
            drawInteraction.current.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }

        if (activeInteraction === 'MODIFY' || activeInteraction === 'SELECT') {
            modifyInteraction.current = new Modify({ source: editSource.current });
            map.addInteraction(modifyInteraction.current);
            modifyInteraction.current.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) {
                    updateVerticesFromFeature(feature);
                }
            });
        }

        if (isSnapping) {
            snapInteraction.current = new Snap({ source: editSource.current });
            map.addInteraction(snapInteraction.current);
        }
    }, [activeInteraction, isSnapping]);

    const handleImportGeoJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const format = new GeoJSON();
                const features = format.readFeatures(JSON.parse(event.target?.result as string), {
                    dataProjection: 'EPSG:4326',
                    featureProjection: 'EPSG:3857'
                });
                editSource.current.addFeatures(features);
                if (features.length > 0) {
                    mapInstance.current?.getView().fit(editSource.current.getExtent(), { padding: [50, 50, 50, 50], duration: 1000 });
                }
                setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: `Đã nhập ${features.length} đối tượng.` });
            } catch (err) {
                setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Định dạng file không hợp lệ.' });
            }
        };
        reader.readAsText(file);
    };

    const handleExportGeoJSON = () => {
        const features = editSource.current.getFeatures();
        if (features.length === 0) return;
        const format = new GeoJSON();
        const json = format.writeFeatures(features, {
            dataProjection: 'EPSG:4326',
            featureProjection: 'EPSG:3857'
        });
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `GeoMaster_Export_${Date.now()}.geojson`;
        a.click();
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Vui lòng chọn bảng đích và đối tượng cần lưu.' });
            return;
        }

        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, {
                dataProjection: 'EPSG:4326',
                featureProjection: 'EPSG:3857'
            });

            // Calculate Area
            const area = getArea(selectedFeature.getGeometry() as Polygon);

            await parcelApi.create(targetTable, {
                sodoto: 'BT-' + Date.now().toString().slice(-4),
                sothua: '0',
                tenchu: 'Biên tập trực tiếp',
                dientich: Math.round(area * 100) / 100,
                geometry: geometry
            });

            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được cập nhật vào PostGIS.' });
        } catch (e: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi lưu trữ', message: e.message });
        } finally {
            setLoading(false);
        }
    };

    const clearWorkspace = () => {
        editSource.current.clear();
        setSelectedFeature(null);
        setVertices([]);
    };

    return (
        <div className="flex h-full w-full bg-slate-950 overflow-hidden font-sans">
            {/* Left Toolbar - Drawing tools */}
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-4 z-20 shadow-2xl">
                <button 
                    onClick={() => setActiveInteraction('SELECT')}
                    className={`p-3 rounded-2xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`}
                    title="Chọn & Chỉnh sửa"
                >
                    <MousePointer2 size={20} />
                </button>
                <button 
                    onClick={() => setActiveInteraction('DRAW')}
                    className={`p-3 rounded-2xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`}
                    title="Vẽ Polygon mới"
                >
                    <Plus size={20} />
                </button>
                <div className="w-8 h-px bg-slate-800" />
                <button 
                    onClick={() => setIsSnapping(!isSnapping)}
                    className={`p-3 rounded-2xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-500 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`}
                    title="Bắt điểm (Snapping)"
                >
                    <Magnet size={20} />
                </button>
                <button 
                    onClick={clearWorkspace}
                    className="p-3 rounded-2xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 transition-all mt-auto"
                    title="Xóa toàn bộ workspace"
                >
                    <Trash2 size={20} />
                </button>
            </div>

            {/* Map Area */}
            <div className="flex-1 relative">
                <div ref={mapElement} className="w-full h-full" />

                {/* Floating Map Controls */}
                <div className="absolute top-6 left-6 flex flex-col gap-2">
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                        {basemaps.map(bm => (
                            <button 
                                key={bm.id} 
                                onClick={() => setActiveBasemapId(bm.id)}
                                className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-800'}`}
                            >
                                {bm.name}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Status Indicator */}
                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'NONE' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">
                            MODE: {activeInteraction} {isSnapping && '+ SNAP'}
                        </span>
                    </div>
                </div>
            </div>

            {/* Right Panel - Properties & Coordinates */}
            <div className="w-80 bg-slate-900 border-l border-slate-800 flex flex-col z-20 shadow-2xl overflow-hidden">
                <div className="p-6 border-b border-slate-800 bg-slate-950/50">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2 mb-1">
                        <List size={16} className="text-blue-400"/> Biên tập thuộc tính
                    </h3>
                    <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Workspace trực tiếp</p>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    {/* Save to DB Section */}
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Lớp đích (PostGIS)</label>
                        <select 
                            className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white focus:border-blue-500 outline-none transition-all"
                            value={targetTable}
                            onChange={e => setTargetTable(e.target.value)}
                        >
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button 
                            onClick={handleSaveToDB}
                            disabled={loading || !selectedFeature}
                            className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30 disabled:grayscale shadow-lg shadow-blue-900/20"
                        >
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO CƠ SỞ DỮ LIỆU
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    {/* Coordinate List */}
                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                <Hash size={12}/> Danh sách tọa độ ({vertices.length})
                            </h4>
                            {selectedFeature && (
                                <span className="text-[9px] font-black text-emerald-500 uppercase tracking-tighter bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">
                                    {Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²
                                </span>
                            )}
                        </div>

                        <div className="bg-slate-950 rounded-2xl border border-slate-800 overflow-hidden">
                            <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
                                <table className="w-full text-[10px] font-mono">
                                    <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                        <tr>
                                            <th className="p-2 text-center w-8">#</th>
                                            <th className="p-2 text-left">X (Longitude)</th>
                                            <th className="p-2 text-left">Y (Latitude)</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-800 text-slate-400">
                                        {vertices.length === 0 ? (
                                            <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Chưa có dữ liệu vẽ</td></tr>
                                        ) : vertices.map((v, i) => (
                                            <tr key={i} className="hover:bg-slate-900/50 transition-colors">
                                                <td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td>
                                                <td className="p-2 truncate">{v.x.toFixed(6)}</td>
                                                <td className="p-2 truncate">{v.y.toFixed(6)}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    {/* Import / Export */}
                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={24} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import GeoJSON</span>
                            <input type="file" className="hidden" accept=".geojson,.json" onChange={handleImportGeoJSON} />
                        </label>
                        <button 
                            onClick={handleExportGeoJSON}
                            disabled={editSource.current.getFeatures().length === 0}
                            className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30 disabled:cursor-not-allowed"
                        >
                            <FileDown size={24} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export GeoJSON</span>
                        </button>
                    </div>
                </div>

                <div className="p-4 bg-slate-950 text-center text-[9px] text-slate-600 font-bold uppercase tracking-widest">
                    V.2.5.0 Spatial Designer
                </div>
            </div>

            {/* Dialog System */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {/* Fixed: Added AlertTriangle icon import to handle error dialog type */}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">Đã hiểu</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

