    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    const graticuleLayer = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ color: 'rgba(255, 255, 255, 0.2)', width: 1, lineDash: [0.5, 4] }),
        showLabels: true,
        wrapX: false,
        zIndex: 5
    }));

    const editStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
        stroke: new style.Stroke({ color: '#3b82f6', width: 3 }),
        image: new style.Circle({ radius: 6, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 2 }) })
    });

    const selectedStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.2)' }),
        stroke: new style.Stroke({ color: '#f97316', width: 4, lineDash: [5, 5] }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#f97316' }), stroke: new style.Stroke({ color: '#fff', width: 2 }) })
    });

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                graticuleLayer.current,
                new VectorLayer({ source: editSource.current, style: editStyle, zIndex: 100 })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 15 }),
            controls: []
        });

        const select = new Select({ style: selectedStyle });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        graticuleLayer.current.setVisible(showGrid);
    }, [showGrid]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();

        // Remove existing draw/modify/snap to re-init
        interactions.getArray()
            .filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap)
            .forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }

        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }

        if (isSnapping) {
            map.addInteraction(new Snap({ source: editSource.current }));
        }
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];

            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm để tạo vùng.");

            // Đảm bảo Polygon khép kín
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) {
                coords.push([...coords[0]] as [number, number]);
            }

            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [50, 50, 50, 50], duration: 1000 });
            setIsManualModalOpen(false);
            setManualCoords('');
            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Đã dựng hình từ danh sách tọa độ.' });
        } catch (e: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi tọa độ', message: e.message });
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (event) => {
            const text = event.target?.result as string;
            if (file.name.endsWith('.geojson') || file.name.endsWith('.json')) {
                try {
                    const format = new GeoJSON();
                    const features = format.readFeatures(JSON.parse(text), { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                    editSource.current.addFeatures(features);
                    setDialog({ isOpen: true, type: 'success', title: 'Import OK', message: `Đã nạp ${features.length} đối tượng.` });
                } catch(err) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi file', message: 'Định dạng GeoJSON không chuẩn.' }); }
            } else {
                handleProcessManualInput(text);
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            const area = getArea(selectedFeature.getGeometry() as Polygon);
            await parcelApi.create(targetTable, {
                sodoto: 'BT-' + Date.now().toString().slice(-4),
                sothua: '0',
                tenchu: 'Biên tập trực tiếp',
                dientich: Math.round(area * 100) / 100,
                geometry: geometry
            });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được cập nhật vào PostGIS.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-slate-950 overflow-hidden font-sans">
            {/* Sidebar Tools */}
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>
                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Lưới bàn cờ"><Grid size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto"><Trash2 size={20}/></button>
            </div>

            {/* Map Area */}
            <div className="flex-1 relative">
                <div ref={mapElement} className="w-full h-full bg-slate-950" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                        {basemaps.map(bm => (
                            <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                        ))}
                    </div>
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'NONE' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">MODE: {activeInteraction} {isSnapping && '+ SNAP'}</span>
                    </div>
                </div>
            </div>

            {/* Right Panel */}
            <div className="w-80 bg-slate-900 border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-slate-950/50">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Thuộc tính hình học
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Lưu vào bảng PostGIS</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Tọa độ đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[300px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Long)</th><th className="p-2 text-left">Y (Lat)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={24} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import File</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            if (features.length === 0) return;
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const url = URL.createObjectURL(blob);
                            const a = document.createElement('a'); a.href = url; a.download = `Export_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={24} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export GeoJSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* Manual Input Modal */}
            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-slate-900 border border-slate-700 rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-slate-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><Keyboard size={20} className="text-blue-400"/> Nhập tọa độ vùng</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-slate-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <div className="p-4 bg-blue-900/10 border border-blue-800/30 rounded-2xl flex gap-3 items-start">
                                <Info size={18} className="text-blue-400 shrink-0 mt-0.5"/>
                                <p className="text-[10px] text-blue-300 leading-relaxed font-bold uppercase">Nhập định dạng X, Y. Mỗi điểm một dòng. <br/>Ví dụ:<br/>106.6, 11.2<br/>106.7, 11.3</p>
                            </div>
                            <textarea value={manualCoords} onChange={e => setManualCoords(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-60 shadow-inner resize-none" placeholder="106.6190, 11.2840..." />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH NGAY</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Dialog */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Layers, Map as MapIcon
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [isVirtualMode, setIsVirtualMode] = useState(false); // Chế độ nền ảo bàn cờ
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));
    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ color: 'rgba(255, 255, 255, 0.1)', width: 1 }),
        showLabels: true,
        wrapX: false,
        zIndex: 5
    }));

    const editStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.15)' }),
        stroke: new style.Stroke({ color: '#3b82f6', width: 2.5 }),
        image: new style.Circle({ radius: 5, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 2 }) })
    });

    const selectedStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.25)' }),
        stroke: new style.Stroke({ color: '#f97316', width: 3.5, lineDash: [6, 6] }),
        image: new style.Circle({ radius: 7, fill: new style.Fill({ color: '#f97316' }), stroke: new style.Stroke({ color: '#fff', width: 2 }) })
    });

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ source: editSource.current, style: editStyle, zIndex: 100 })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 16 }),
            controls: []
        });

        const select = new Select({ style: selectedStyle });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            if (feature) setActiveInteraction('SELECT');
        });

        mapInstance.current = map;
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    // Toggle Virtual Mode (Checkerboard)
    useEffect(() => {
        if (baseLayerRef.current) {
            baseLayerRef.current.setVisible(!isVirtualMode);
        }
    }, [isVirtualMode]);

    // Handle Basemap change
    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId || isVirtualMode) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps, isVirtualMode]);

    // Update Interactions
    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;

        const interactions = map.getInteractions();
        interactions.getArray()
            .filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap)
            .forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }

        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }

        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const parseCoordinates = (text: string) => {
        const lines = text.trim().split(/[\n;]+/);
        const coords = lines.map(line => {
            const parts = line.split(/[,\s\t]+/).filter(Boolean);
            if (parts.length < 2) return null;
            const x = parseFloat(parts[0]);
            const y = parseFloat(parts[1]);
            return isNaN(x) || isNaN(y) ? null : [x, y];
        }).filter(Boolean) as [number, number][];

        if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm để tạo vùng.");

        // Khép góc nếu cần
        if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) {
            coords.push([...coords[0]] as [number, number]);
        }
        return coords;
    };

    const handleProcessManualInput = (inputText: string) => {
        try {
            const coords = parseCoordinates(inputText);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 1000 });
            setIsManualModalOpen(false);
            setManualCoords('');
            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Đã dựng hình từ danh sách tọa độ.' });
        } catch (e: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi tọa độ', message: e.message });
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (event) => {
            const text = event.target?.result as string;
            if (file.name.match(/\.(geojson|json)$/i)) {
                try {
                    const format = new GeoJSON();
                    const features = format.readFeatures(JSON.parse(text), { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                    editSource.current.addFeatures(features);
                    setDialog({ isOpen: true, type: 'success', title: 'Import OK', message: `Đã nạp ${features.length} đối tượng.` });
                } catch(err) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi file', message: 'Định dạng GeoJSON không hợp lệ.' }); }
            } else {
                handleProcessManualInput(text);
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            const area = getArea(selectedFeature.getGeometry() as Polygon);
            await parcelApi.create(targetTable, {
                sodoto: 'BT-' + Date.now().toString().slice(-4),
                sothua: '0',
                tenchu: 'Biên tập trực tiếp',
                dientich: Math.round(area * 100) / 100,
                geometry: geometry
            });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được cập nhật vào PostGIS.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-slate-950 overflow-hidden font-sans">
            <style>{`
                .checkerboard {
                    background-image: 
                        linear-gradient(45deg, #161b22 25%, transparent 25%), 
                        linear-gradient(-45deg, #161b22 25%, transparent 25%), 
                        linear-gradient(45deg, transparent 75%, #161b22 75%), 
                        linear-gradient(-45deg, transparent 75%, #161b22 75%);
                    background-size: 40px 40px;
                    background-position: 0 0, 0 20px, 20px -20px, -20px 0px;
                    background-color: #0d1117;
                }
            `}</style>

            {/* Left Toolbar */}
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>
                <button onClick={() => setIsVirtualMode(!isVirtualMode)} className={`p-3 rounded-xl transition-all ${isVirtualMode ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ nền ảo bàn cờ"><Grid size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm (Snapping)"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto"><Trash2 size={20}/></button>
            </div>

            {/* Map Area */}
            <div className={`flex-1 relative ${isVirtualMode ? 'checkerboard' : ''}`}>
                <div ref={mapElement} className={`w-full h-full ${isVirtualMode ? 'opacity-90' : 'opacity-100'}`} />

                {/* Floating Map Controls */}
                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {!isVirtualMode && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                    {isVirtualMode && (
                        <div className="bg-indigo-600 px-4 py-2 rounded-xl shadow-2xl flex items-center gap-2 text-white border border-indigo-400/50 animate-in fade-in slide-in-from-left-4">
                            <Grid size={16}/>
                            <span className="text-[10px] font-black uppercase tracking-widest">Không gian ảo đang bật</span>
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction} {isSnapping && '+ SNAP'}</span>
                    </div>
                </div>
            </div>

            {/* Right Panel */}
            <div className="w-80 bg-slate-900 border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-slate-950/50">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Biên tập hình học
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Lớp đích PostGIS</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30 shadow-lg shadow-blue-900/30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[350px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Chưa có dữ liệu</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={24} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white text-center leading-tight">Import Tọa độ<br/>(TXT/CSV/JSON)</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            if (features.length === 0) return;
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const url = URL.createObjectURL(blob);
                            const a = document.createElement('a'); a.href = url; a.download = `GeoDesign_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={24} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export GeoJSON</span>
                        </button>
                    </div>
                </div>

                <div className="p-4 bg-slate-950 text-center border-t border-slate-800">
                    <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest">Spatial Designer v2.5</p>
                </div>
            </div>

            {/* Manual Input Modal */}
            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-slate-900 border border-slate-700 rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-slate-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><Keyboard size={20} className="text-blue-400"/> Nhập tọa độ vùng</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-slate-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <div className="p-4 bg-blue-900/10 border border-blue-800/30 rounded-2xl flex gap-3 items-start">
                                <Info size={18} className="text-blue-400 shrink-0 mt-0.5"/>
                                <p className="text-[10px] text-blue-300 leading-relaxed font-bold uppercase">Nhập định dạng X, Y. Phân cách bởi dấu phẩy hoặc khoảng trắng. Mỗi điểm một dòng.<br/><br/>Ví dụ:<br/>106.61, 11.28<br/>106.62, 11.29</p>
                            </div>
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none custom-scrollbar" 
                                placeholder="106.6190, 11.2840&#10;106.6200, 11.2850..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all active:scale-95 shadow-xl shadow-blue-900/20">DỰNG HÌNH NGAY</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Dialog System */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">Đã hiểu</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [isVirtualMode, setIsVirtualMode] = useState(true); // Mặc định bật chế độ ảo
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    // Grid Layer không hiển thị nhãn (showLabels: false)
    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ color: 'rgba(255, 255, 255, 0.05)', width: 1 }),
        showLabels: false, // Bỏ tọa độ hàng cột
        wrapX: false,
        zIndex: 5
    }));

    // Style cho Polygon và số hiệu đỉnh
    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            // Đánh số hiệu 1, 2, 3... tại các đỉnh
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(!isVirtualMode);
    }, [isVirtualMode]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId || isVirtualMode) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps, isVirtualMode]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <style>{`
                .virtual-bg {
                    background-image: 
                        linear-gradient(rgba(255,255,255,.03) 1px, transparent 1px),
                        linear-gradient(90deg, rgba(255,255,255,.03) 1px, transparent 1px);
                    background-size: 50px 50px;
                    background-color: #05070a;
                }
            `}</style>

            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ"><Keyboard size={20}/></button>
                <button onClick={() => setIsVirtualMode(!isVirtualMode)} className={`p-3 rounded-xl transition-all ${isVirtualMode ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Lớp ảo bàn cờ"><Grid size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto"><Trash2 size={20}/></button>
            </div>

            <div className={`flex-1 relative ${isVirtualMode ? 'virtual-bg' : ''}`}>
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {!isVirtualMode && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-slate-900 border border-slate-700 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-slate-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-slate-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [isVirtualMode, setIsVirtualMode] = useState(true); // Mặc định bật chế độ ảo
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    // Grid Layer không hiển thị nhãn (showLabels: false)
    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ color: 'rgba(255, 255, 255, 0.05)', width: 1 }),
        showLabels: false, // Bỏ tọa độ hàng cột
        wrapX: false,
        zIndex: 5
    }));

    // Style cho Polygon và số hiệu đỉnh
    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            // Đánh số hiệu 1, 2, 3... tại các đỉnh
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(!isVirtualMode);
    }, [isVirtualMode]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId || isVirtualMode) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps, isVirtualMode]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    // Added handleFileUpload to process imported GeoJSON files and sync with the UI
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = event.target?.result as string;
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let features: Feature[] = [];

                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else {
                    const geom = format.readGeometry(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: 'Dữ liệu không đúng định dạng GeoJSON hoặc lỗi đọc file.' 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <style>{`
                .virtual-bg {
                    background-image: 
                        linear-gradient(rgba(255,255,255,.03) 1px, transparent 1px),
                        linear-gradient(90deg, rgba(255,255,255,.03) 1px, transparent 1px);
                    background-size: 50px 50px;
                    background-color: #05070a;
                }
            `}</style>

            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ"><Keyboard size={20}/></button>
                <button onClick={() => setIsVirtualMode(!isVirtualMode)} className={`p-3 rounded-xl transition-all ${isVirtualMode ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Lớp ảo bàn cờ"><Grid size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto"><Trash2 size={20}/></button>
            </div>

            <div className={`flex-1 relative ${isVirtualMode ? 'virtual-bg' : ''}`}>
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {!isVirtualMode && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-slate-900 border border-slate-700 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-slate-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [isVirtualMode, setIsVirtualMode] = useState(true); // Mặc định bật chế độ ảo
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    // Style cho Polygon và số hiệu đỉnh (1, 2, 3...)
    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            // Đánh số hiệu 1, 2, 3... tại các đỉnh
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(!isVirtualMode);
    }, [isVirtualMode]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId || isVirtualMode) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps, isVirtualMode]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = event.target?.result as string;
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let features: Feature[] = [];

                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else {
                    const geom = format.readGeometry(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: 'Dữ liệu không đúng định dạng GeoJSON hoặc lỗi đọc file.' 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <style>{`
                .virtual-bg {
                    background-image: 
                        linear-gradient(rgba(255,255,255,.02) 1px, transparent 1px),
                        linear-gradient(90deg, rgba(255,255,255,.02) 1px, transparent 1px);
                    background-size: 40px 40px;
                    background-color: #05070a;
                }
            `}</style>

            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ"><Keyboard size={20}/></button>
                <button onClick={() => setIsVirtualMode(!isVirtualMode)} className={`p-3 rounded-xl transition-all ${isVirtualMode ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Lớp ảo bàn cờ"><Grid size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto"><Trash2 size={20}/></button>
            </div>

            <div className={`flex-1 relative ${isVirtualMode ? 'virtual-bg' : ''}`}>
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {!isVirtualMode && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, Layers
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true); // Trạng thái hiện bản đồ nền
    const [showGrid, setShowGrid] = useState(true); // Trạng thái hiện lưới Graticule
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    // Khởi tạo Graticule (Lưới tọa độ)
    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, // Không hiện nhãn số để tránh rối
        wrapX: false,
        zIndex: 5
    }));

    // Style cho Polygon và số hiệu đỉnh
    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    // Điều khiển ẩn hiện lớp nền và lưới
    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = event.target?.result as string;
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let features: Feature[] = [];

                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else {
                    const geom = format.readGeometry(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: 'Dữ liệu không đúng định dạng GeoJSON hoặc lỗi đọc file.' 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền (Referral)">
                    <MapIcon size={20}/>
                </button>

                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ">
                    <Grid size={20}/>
                </button>

                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>

                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm Snapping"><Magnet size={20}/></button>

                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                    {!showBasemap && (
                        <div className="bg-slate-900/80 px-4 py-2 rounded-xl shadow-2xl flex items-center gap-2 text-slate-400 border border-slate-700/50">
                            <Info size={14}/>
                            <span className="text-[10px] font-black uppercase tracking-widest">Bản đồ nền đang ẩn</span>
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, Layers,
    Search, Maximize, MapPin, Navigation
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    // Khởi tạo Graticule (Lưới tọa độ)
    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    // Style cho Polygon và số hiệu đỉnh
    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            // Giả định tọa độ nhập vào là EPSG:3857 hoặc chuyển đổi nếu cần
            // Ở đây mặc định xử lý như tọa độ bản đồ hiện tại
            mapInstance.current.getView().animate({
                center: [x, y],
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = event.target?.result as string;
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let features: Feature[] = [];

                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else {
                    const geom = format.readGeometry(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: 'Dữ liệu không đúng định dạng GeoJSON hoặc lỗi đọc file.' 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh đỉnh (M)"><Move size={20}/></button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)">
                    <Maximize size={20}/>
                </button>

                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)">
                    <Search size={20}/>
                </button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền">
                    <MapIcon size={20}/>
                </button>

                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ">
                    <Grid size={20}/>
                </button>

                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay">
                    <Keyboard size={20}/>
                </button>

                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bắt điểm Snapping">
                    <Magnet size={20}/>
                </button>

                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                    {!showBasemap && (
                        <div className="bg-slate-900/80 px-4 py-2 rounded-xl shadow-2xl flex items-center gap-2 text-slate-400 border border-slate-700/50">
                            <Info size={14}/>
                            <span className="text-[10px] font-black uppercase tracking-widest">Bản đồ nền đang ẩn</span>
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* MODAL TÌM TỌA ĐỘ */}
            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2">
                                <Navigation size={20} className="text-blue-500"/> Di chuyển đến điểm
                            </h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Kinh độ / X (Longitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="106.xxxxxx"
                                    value={searchCoords.x}
                                    onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Vĩ độ / Y (Latitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="11.xxxxxx"
                                    value={searchCoords.y}
                                    onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}
                                />
                            </div>
                            <button 
                                onClick={handleGoToCoordinate}
                                className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-blue-900/30 transition-all active:scale-95"
                            >
                                <MapPin size={16}/> DI CHUYỂN NGAY
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true); // Mặc định hiện bản đồ nền
    const [showGrid, setShowGrid] = useState(true); // Mặc định hiện lưới tọa độ
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' }); // Kinh độ, Vĩ độ
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    // Khởi tạo Graticule (Lưới tọa độ chuẩn)
    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    // Style cho Polygon và số hiệu đỉnh
    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        if (geom instanceof Polygon) {
            const coords = geom.getCoordinates()[0];
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x); // Lon
        const y = parseFloat(searchCoords.y); // Lat
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            // Chuyển từ Lon/Lat (WGS84) sang Web Mercator (Bản đồ)
            const center = proj.fromLonLat([x, y]);
            mapInstance.current.getView().animate({
                center: center,
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    // Điều khiển ẩn hiện lớp nền và lưới Graticule
    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = event.target?.result as string;
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let features: Feature[] = [];

                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else {
                    const geom = format.readGeometry(content, { 
                        dataProjection: 'EPSG:4326', 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: 'Dữ liệu không đúng định dạng GeoJSON hoặc lỗi đọc file.' 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)">
                    <Maximize size={20}/>
                </button>

                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)">
                    <Search size={20}/>
                </button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền">
                    <MapIcon size={20}/>
                </button>

                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ">
                    <Grid size={20}/>
                </button>

                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay">
                    <Keyboard size={20}/>
                </button>

                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)">
                    <Magnet size={20}/>
                </button>

                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                    {!showBasemap && (
                        <div className="bg-slate-900/80 px-4 py-2 rounded-xl shadow-2xl flex items-center gap-2 text-slate-400 border border-slate-700/50">
                            <Info size={14}/>
                            <span className="text-[10px] font-black uppercase tracking-widest">Bản đồ nền đang ẩn</span>
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as Polygon)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* MODAL TÌM TỌA ĐỘ CHUẨN */}
            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2">
                                <Navigation size={20} className="text-blue-500"/> Di chuyển đến điểm
                            </h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Kinh độ / X (Longitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="106.xxxxxx"
                                    value={searchCoords.x}
                                    onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Vĩ độ / Y (Latitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="11.xxxxxx"
                                    value={searchCoords.y}
                                    onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}
                                />
                            </div>
                            <button 
                                onClick={handleGoToCoordinate}
                                className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-blue-900/30 transition-all active:scale-95"
                            >
                                <MapPin size={16}/> DI CHUYỂN NGAY
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point, MultiPolygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            coords = geom.getCoordinates()[0][0];
        }

        if (coords.length > 0) {
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            coords = geom.getCoordinates()[0][0];
        }

        if (coords.length > 0) {
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            const center = proj.fromLonLat([x, y]);
            mapInstance.current.getView().animate({
                center: center,
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = (event.target?.result as string).trim();
                const content = JSON.parse(text);
                const format = new GeoJSON();

                // Helper để đoán projection từ tọa độ đầu tiên tìm thấy
                let guessedDataProj = 'EPSG:4326';
                try {
                    let firstCoord: any = null;
                    if (content.type === 'FeatureCollection' && content.features?.[0]?.geometry?.coordinates) {
                        const firstFeat = content.features[0].geometry.coordinates;
                        firstCoord = Array.isArray(firstFeat[0]) ? (Array.isArray(firstFeat[0][0]) ? firstFeat[0][0][0] : firstFeat[0][0]) : firstFeat[0];
                    } else if (content.type === 'Feature' && content.geometry?.coordinates) {
                        const coords = content.geometry.coordinates;
                        firstCoord = Array.isArray(coords[0]) ? (Array.isArray(coords[0][0]) ? coords[0][0][0] : coords[0][0]) : coords[0];
                    }

                    if (firstCoord && (Math.abs(firstCoord) > 2000000)) {
                        guessedDataProj = 'EPSG:3857';
                    }
                } catch (e) {}

                let features: Feature[] = [];
                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: guessedDataProj, 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: guessedDataProj, 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else if (content.type === 'Polygon' || content.type === 'MultiPolygon') {
                    const geom = format.readGeometry(content, { 
                        dataProjection: guessedDataProj, 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                    setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: `Đã nạp ${features.length} đối tượng vào bản vẽ.` });
                } else {
                    throw new Error("Không tìm thấy dữ liệu hình học hợp lệ trong tệp.");
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: `Dữ liệu không đúng định dạng GeoJSON hoặc lỗi đọc nội dung: ${err.message}` 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)">
                    <Maximize size={20}/>
                </button>

                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)">
                    <Search size={20}/>
                </button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền">
                    <MapIcon size={20}/>
                </button>

                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ">
                    <Grid size={20}/>
                </button>

                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay">
                    <Keyboard size={20}/>
                </button>

                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)">
                    <Magnet size={20}/>
                </button>

                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as any)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X (Kinh độ)</th><th className="p-2 text-left">Y (Vĩ độ)</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(6)}</td><td className="p-2">{v.y.toFixed(6)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2">
                                <Navigation size={20} className="text-blue-500"/> Di chuyển đến điểm
                            </h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Kinh độ / X (Longitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="106.xxxxxx"
                                    value={searchCoords.x}
                                    onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Vĩ độ / Y (Latitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="11.xxxxxx"
                                    value={searchCoords.y}
                                    onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}
                                />
                            </div>
                            <button 
                                onClick={handleGoToCoordinate}
                                className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-blue-900/30 transition-all active:scale-95"
                            >
                                <MapPin size={16}/> DI CHUYỂN NGAY
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point, MultiPolygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000 (EPSG:9210 - Kinh tuyến trục 105.75 cho khu vực miền Nam)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            // Lấy ring đầu tiên của polygon đầu tiên trong multipolygon
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            const center = proj.fromLonLat([x, y]);
            mapInstance.current.getView().animate({
                center: center,
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    // Hàm đệ quy để tìm tọa độ đầu tiên (x, y) trong mảng coordinates bất kể cấp độ lồng nhau
    const getFirstCoordFromNested = (arr: any): [number, number] | null => {
        if (!Array.isArray(arr) || arr.length === 0) return null;
        if (typeof arr[0] === 'number' && typeof arr[1] === 'number') return [arr[0], arr[1]];
        return getFirstCoordFromNested(arr[0]);
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = (event.target?.result as string).trim();
                const content = JSON.parse(text);
                const format = new GeoJSON();

                // --- BỘ GIẢI MÃ HỆ TỌA ĐỘ THÔNG MINH ---
                let guessedDataProj = 'EPSG:4326';
                try {
                    let firstCoord: [number, number] | null = null;

                    // Duyệt cấu trúc GeoJSON để tìm điểm tọa độ đầu tiên
                    if (content.type === 'FeatureCollection' && content.features?.[0]?.geometry?.coordinates) {
                        firstCoord = getFirstCoordFromNested(content.features[0].geometry.coordinates);
                    } else if (content.type === 'Feature' && content.geometry?.coordinates) {
                        firstCoord = getFirstCoordFromNested(content.geometry.coordinates);
                    } else if (content.coordinates) {
                        firstCoord = getFirstCoordFromNested(content.coordinates);
                    }

                    if (firstCoord) {
                        const [x, y] = firstCoord;
                        // 1. Nhận diện VN-2000 (X: 300k-900k, Y: 1M-2.5M)
                        if (x > 300000 && x < 900000 && y > 1000000 && y < 2500000) {
                            guessedDataProj = 'EPSG:9210';
                        }
                        // 2. Nhận diện Web Mercator (Số rất lớn > 2M)
                        else if (Math.abs(x) > 2000000) {
                            guessedDataProj = 'EPSG:3857';
                        }
                    }
                } catch (e) {
                    console.warn("Guess projection failed, defaulting to EPSG:4326");
                }

                let features: Feature[] = [];
                if (content.type === 'FeatureCollection') {
                    features = format.readFeatures(content, { 
                        dataProjection: guessedDataProj, 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature[];
                } else if (content.type === 'Feature') {
                    const feature = format.readFeature(content, { 
                        dataProjection: guessedDataProj, 
                        featureProjection: 'EPSG:3857' 
                    }) as Feature;
                    features = [feature];
                } else {
                    const geom = format.readGeometry(content, { 
                        dataProjection: guessedDataProj, 
                        featureProjection: 'EPSG:3857' 
                    });
                    features = [new Feature({ geometry: geom })];
                }

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);

                    const extent = editSource.current.getExtent();
                    mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800 });
                    setDialog({ 
                        isOpen: true, 
                        type: 'success', 
                        title: 'Thành công', 
                        message: `Đã nạp ${features.length} đối tượng. Hệ tọa độ nhận diện: ${guessedDataProj === 'EPSG:9210' ? 'VN-2000' : guessedDataProj === 'EPSG:3857' ? 'Web Mercator' : 'WGS84'}` 
                    });
                } else {
                    throw new Error("Không tìm thấy dữ liệu hình học hợp lệ trong tệp.");
                }
            } catch (err: any) {
                setDialog({ 
                    isOpen: true, 
                    type: 'error', 
                    title: 'Lỗi nạp file', 
                    message: `Dữ liệu không đúng định dạng hoặc lỗi đọc nội dung: ${err.message}` 
                });
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)">
                    <Maximize size={20}/>
                </button>

                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)">
                    <Search size={20}/>
                </button>

                <div className="w-8 h-px bg-slate-800 my-2" />

                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền">
                    <MapIcon size={20}/>
                </button>

                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ">
                    <Grid size={20}/>
                </button>

                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay">
                    <Keyboard size={20}/>
                </button>

                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)">
                    <Magnet size={20}/>
                </button>

                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />

                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-80 bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a]">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <List size={16} className="text-blue-400"/> Cấu trúc tọa độ
                    </h3>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Bảng PostGIS lưu trữ</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách đỉnh ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as any)).toLocaleString()} m²</span>}
                        </div>
                        <div className="bg-slate-950 rounded-2xl border border-slate-800 max-h-[400px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-[10px] font-mono">
                                <thead className="bg-slate-900 text-slate-500 sticky top-0">
                                    <tr><th className="p-2 text-center w-8">#</th><th className="p-2 text-left">X</th><th className="p-2 text-left">Y</th></tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? <tr><td colSpan={3} className="p-8 text-center italic text-slate-600 uppercase text-[9px] font-bold">Trống</td></tr> : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors"><td className="p-2 text-center text-slate-600 font-bold">{i + 1}</td><td className="p-2">{v.x.toFixed(3)}</td><td className="p-2">{v.y.toFixed(3)}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export</span>
                        </button>
                    </div>
                </div>
            </div>

            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2">
                                <Navigation size={20} className="text-blue-500"/> Di chuyển đến điểm
                            </h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Kinh độ / X (Longitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="106.xxxxxx"
                                    value={searchCoords.x}
                                    onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Vĩ độ / Y (Latitude)</label>
                                <input 
                                    className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all"
                                    placeholder="11.xxxxxx"
                                    value={searchCoords.y}
                                    onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}
                                />
                            </div>
                            <button 
                                onClick={handleGoToCoordinate}
                                className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-blue-900/30 transition-all active:scale-95"
                            >
                                <MapPin size={16}/> DI CHUYỂN NGAY
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea 
                                value={manualCoords} 
                                onChange={e => setManualCoords(e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" 
                                placeholder="106.619, 11.284&#10;106.620, 11.285..." 
                            />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation, Edit3, ClipboardList, Download
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point, MultiPolygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Editing State
    const [editingVertexIndex, setEditingVertexIndex] = useState<number | null>(null);

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const updateGeometryFromVertices = (newVertices: {x: number, y: number}[]) => {
        if (!selectedFeature) return;
        const coords = newVertices.map(v => [v.x, v.y]);
        if (coords.length >= 3) {
            coords.push([...coords[0]]); // Đóng vùng
            const geom = selectedFeature.getGeometry();
            if (geom instanceof Polygon) {
                geom.setCoordinates([coords]);
            } else if (geom instanceof MultiPolygon) {
                geom.setCoordinates([[coords]]);
            }
            selectedFeature.changed();
        }
    };

    const handleDeleteVertex = (index: number) => {
        if (vertices.length <= 3) {
            setDialog({ isOpen: true, type: 'error', title: 'Không thể xóa', message: 'Vùng phải có ít nhất 3 đỉnh.' });
            return;
        }
        const nextVertices = vertices.filter((_, i) => i !== index);
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleAddVertex = () => {
        const last = vertices[vertices.length - 1] || { x: 0, y: 0 };
        const nextVertices = [...vertices, { x: last.x + 10, y: last.y + 10 }];
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleUpdateVertex = (index: number, axis: 'x' | 'y', value: string) => {
        const num = parseFloat(value);
        if (isNaN(num)) return;
        const nextVertices = vertices.map((v, i) => i === index ? { ...v, [axis]: num } : v);
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleExportCoordsTxt = () => {
        if (vertices.length === 0) return;
        let content = "STT\tX (Kinh độ)\tY (Vĩ độ)\n";
        vertices.forEach((v, i) => {
            content += `${i + 1}\t${v.x.toFixed(6)}\t${v.y.toFixed(6)}\n`;
        });
        const blob = new Blob([content], { type: 'text/plain' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = `ToaDo_${Date.now()}.txt`;
        a.click();
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            const center = proj.fromLonLat([x, y]);
            mapInstance.current.getView().animate({
                center: center,
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                return [parseFloat(parts[0]), parseFloat(parts[1])];
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const getFirstCoordFromNested = (arr: any): [number, number] | null => {
        if (!Array.isArray(arr) || arr.length === 0) return null;
        if (typeof arr[0] === 'number' && typeof arr[1] === 'number') return [arr[0], arr[1]];
        return getFirstCoordFromNested(arr[0]);
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = (event.target?.result as string).trim();
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let guessedDataProj = 'EPSG:4326';
                try {
                    let firstCoord: [number, number] | null = null;
                    if (content.type === 'FeatureCollection' && content.features?.[0]?.geometry?.coordinates) firstCoord = getFirstCoordFromNested(content.features[0].geometry.coordinates);
                    else if (content.type === 'Feature' && content.geometry?.coordinates) firstCoord = getFirstCoordFromNested(content.geometry.coordinates);
                    else if (content.coordinates) firstCoord = getFirstCoordFromNested(content.coordinates);
                    if (firstCoord) {
                        const [x, y] = firstCoord;
                        if (x > 300000 && x < 900000 && y > 1000000 && y < 2500000) guessedDataProj = 'EPSG:9210';
                        else if (Math.abs(x) > 2000000) guessedDataProj = 'EPSG:3857';
                    }
                } catch (e) {}

                let features: Feature[] = [];
                if (content.type === 'FeatureCollection') features = format.readFeatures(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) as Feature[];
                else if (content.type === 'Feature') features = [format.readFeature(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) as Feature];
                else features = [new Feature({ geometry: format.readGeometry(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) })];

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);
                    mapInstance.current?.getView().fit(editSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
                    setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: `Đã nạp ${features.length} đối tượng.` });
                }
            } catch (err: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: `Lỗi đọc nội dung: ${err.message}` }); }
            finally { e.target.value = ''; }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans text-white">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)"><Maximize size={20}/></button>
                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)"><Search size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền"><MapIcon size={20}/></button>
                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ"><Grid size={20}/></button>
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />
                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>
                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-[400px] bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a] flex items-center justify-between">
                    <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                        <ClipboardList size={16} className="text-blue-400"/> Biên tập đỉnh
                    </h3>
                    <div className="flex gap-2">
                        <button onClick={handleExportCoordsTxt} className="p-2 text-slate-400 hover:text-white transition-colors" title="Xuất danh sách tọa độ (TXT)"><Download size={16}/></button>
                        <button onClick={handleAddVertex} className="p-2 text-emerald-500 hover:text-emerald-400 transition-colors" title="Thêm đỉnh mới"><Plus size={18}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Lưu trữ mục tiêu</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách tọa độ ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as any)).toLocaleString()} m²</span>}
                        </div>

                        <div className="bg-slate-950 rounded-2xl border border-slate-800 overflow-hidden">
                            <table className="w-full text-[10px] font-mono border-collapse">
                                <thead className="bg-slate-900 text-slate-500">
                                    <tr>
                                        <th className="p-3 text-center w-10 border-b border-slate-800">#</th>
                                        <th className="p-3 text-left border-b border-slate-800">X (Kinh độ)</th>
                                        <th className="p-3 text-left border-b border-slate-800">Y (Vĩ độ)</th>
                                        <th className="p-3 text-center w-10 border-b border-slate-800"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? (
                                        <tr><td colSpan={4} className="p-12 text-center italic text-slate-600 uppercase text-[9px] font-bold tracking-widest">Không có điểm nào</td></tr>
                                    ) : vertices.map((v, i) => (
                                        <tr key={i} className="hover:bg-slate-900/50 transition-colors group">
                                            <td className="p-3 text-center text-slate-600 font-bold border-r border-slate-800">{i + 1}</td>
                                            <td className="p-2 border-r border-slate-800">
                                                <input 
                                                    type="text"
                                                    value={v.x.toFixed(6)}
                                                    onChange={(e) => handleUpdateVertex(i, 'x', e.target.value)}
                                                    className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded p-1 outline-none text-blue-400 font-bold"
                                                />
                                            </td>
                                            <td className="p-2 border-r border-slate-800">
                                                <input 
                                                    type="text"
                                                    value={v.y.toFixed(6)}
                                                    onChange={(e) => handleUpdateVertex(i, 'y', e.target.value)}
                                                    className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded p-1 outline-none text-emerald-400 font-bold"
                                                />
                                            </td>
                                            <td className="p-2 text-center">
                                                <button 
                                                    onClick={() => handleDeleteVertex(i)}
                                                    className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                                                >
                                                    <Trash2 size={14}/>
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                        <p className="text-[9px] text-slate-500 italic px-1">* Bạn có thể chỉnh sửa trực tiếp giá trị X, Y trong bảng để cập nhật hình vẽ.</p>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export GeoJSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* MODALS */}
            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><Navigation size={20} className="text-blue-500"/> Di chuyển đến điểm</h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Kinh độ / X</label>
                                <input className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all" value={searchCoords.x} onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Vĩ độ / Y</label>
                                <input className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all" value={searchCoords.y} onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}/>
                            </div>
                            <button onClick={handleGoToCoordinate} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95">DI CHUYỂN NGAY</button>
                        </div>
                    </div>
                </div>
            )}

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <textarea value={manualCoords} onChange={e => setManualCoords(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" placeholder="106.619, 11.284&#10;106.620, 11.285..." />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation, Edit3, ClipboardList, Download, Settings2
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point, MultiPolygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000 (EPSG:9210 - Kinh tuyến trục 105.75 cho khu vực miền Nam)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);

    // Vertices luôn lưu ở EPSG:3857 để đồng bộ với Map
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [coordSystem, setCoordSystem] = useState<'WGS84' | 'VN2000'>('VN2000');

    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            // Lọc bỏ điểm trùng cuối để quản lý bảng cho gọn
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const updateGeometryFromVertices = (newVertices: {x: number, y: number}[]) => {
        if (!selectedFeature) return;
        const coords = newVertices.map(v => [v.x, v.y]);
        if (coords.length >= 3) {
            // Đóng vùng (điểm cuối = điểm đầu)
            coords.push([...coords[0]]);
            const geom = selectedFeature.getGeometry();
            if (geom instanceof Polygon) {
                geom.setCoordinates([coords]);
            } else if (geom instanceof MultiPolygon) {
                geom.setCoordinates([[coords]]);
            }
            selectedFeature.changed();
        }
    };

    // --- CÁC HÀM XỬ LÝ BIÊN TẬP ĐỈNH ---

    const handleDeleteVertex = (index: number) => {
        if (vertices.length <= 3) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Vùng phải có ít nhất 3 đỉnh để hình thành đa giác.' });
            return;
        }
        const nextVertices = vertices.filter((_, i) => i !== index);
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleAddVertex = () => {
        if (vertices.length === 0) return;
        const last = vertices[vertices.length - 1];
        // Chèn 1 điểm mới lệch đi một chút so với điểm cuối
        const nextVertices = [...vertices, { x: last.x + 2, y: last.y + 2 }];
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleUpdateVertex = (index: number, axis: 'x' | 'y', value: string) => {
        const num = parseFloat(value);
        if (isNaN(num)) return;

        let finalX = vertices[index].x;
        let finalY = vertices[index].y;

        if (coordSystem === 'VN2000') {
            // Nếu đang sửa ở hệ VN2000, phải convert ngược về 3857 để Map hiểu
            const currentVn = proj.transform([vertices[index].x, vertices[index].y], 'EPSG:3857', 'EPSG:9210');
            const newVn = axis === 'x' ? [num, currentVn[1]] : [currentVn[0], num];
            const backToMap = proj.transform(newVn, 'EPSG:9210', 'EPSG:3857');
            finalX = backToMap[0];
            finalY = backToMap[1];
        } else {
            // Nếu đang sửa ở hệ WGS84
            const currentWgs = proj.transform([vertices[index].x, vertices[index].y], 'EPSG:3857', 'EPSG:4326');
            const newWgs = axis === 'x' ? [num, currentWgs[1]] : [currentWgs[0], num];
            const backToMap = proj.transform(newWgs, 'EPSG:4326', 'EPSG:3857');
            finalX = backToMap[0];
            finalY = backToMap[1];
        }

        const nextVertices = [...vertices];
        nextVertices[index] = { x: finalX, y: finalY };
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    // --- HÀM XUẤT TỌA ĐỘ ---

    const handleExportCoordsTxt = () => {
        if (vertices.length === 0) return;

        let content = `DANH SÁCH TỌA ĐỘ THỬA ĐẤT - HỆ: ${coordSystem}\n`;
        content += `STT\tX (m)\tY (m)\n`;
        content += `------------------------------------\n`;

        vertices.forEach((v, i) => {
            let displayX, displayY;
            if (coordSystem === 'VN2000') {
                const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:9210');
                displayX = p[0].toFixed(3);
                displayY = p[1].toFixed(3);
            } else {
                const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:4326');
                displayX = p[0].toFixed(8);
                displayY = p[1].toFixed(8);
            }
            content += `${i + 1}\t${displayX}\t${displayY}\n`;
        });

        // Điểm cuối trùng đầu cho khép góc
        const vFirst = vertices[0];
        let fx, fy;
        if (coordSystem === 'VN2000') {
            const p = proj.transform([vFirst.x, vFirst.y], 'EPSG:3857', 'EPSG:9210');
            fx = p[0].toFixed(3); fy = p[1].toFixed(3);
        } else {
            const p = proj.transform([vFirst.x, vFirst.y], 'EPSG:3857', 'EPSG:4326');
            fx = p[0].toFixed(8); fy = p[1].toFixed(8);
        }
        content += `${vertices.length + 1}\t${fx}\t${fy}\n`;

        const blob = new Blob([content], { type: 'text/plain' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = `ToaDo_VN2000_${Date.now()}.txt`;
        a.click();
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            // Mặc định Go to dùng VN2000 nếu số lớn
            let center;
            if (Math.abs(x) > 100000) {
                center = proj.transform([x, y], 'EPSG:9210', 'EPSG:3857');
            } else {
                center = proj.fromLonLat([x, y]);
            }
            mapInstance.current.getView().animate({
                center: center,
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                const x = parseFloat(parts[0]);
                const y = parseFloat(parts[1]);
                // Tự động nhận diện VN2000 khi nhập tay
                if (x > 300000 && x < 900000) {
                    return proj.transform([x, y], 'EPSG:9210', 'EPSG:3857');
                }
                return proj.fromLonLat([x, y]);
            }).filter(Boolean) as [number, number][];

            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);

            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const getFirstCoordFromNested = (arr: any): [number, number] | null => {
        if (!Array.isArray(arr) || arr.length === 0) return null;
        if (typeof arr[0] === 'number' && typeof arr[1] === 'number') return [arr[0], arr[1]];
        return getFirstCoordFromNested(arr[0]);
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = (event.target?.result as string).trim();
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let guessedDataProj = 'EPSG:4326';
                try {
                    let firstCoord: [number, number] | null = null;
                    if (content.type === 'FeatureCollection' && content.features?.[0]?.geometry?.coordinates) firstCoord = getFirstCoordFromNested(content.features[0].geometry.coordinates);
                    else if (content.type === 'Feature' && content.geometry?.coordinates) firstCoord = getFirstCoordFromNested(content.geometry.coordinates);
                    else if (content.coordinates) firstCoord = getFirstCoordFromNested(content.coordinates);
                    if (firstCoord) {
                        const [x, y] = firstCoord;
                        if (x > 300000 && x < 900000 && y > 1000000 && y < 2500000) guessedDataProj = 'EPSG:9210';
                        else if (Math.abs(x) > 2000000) guessedDataProj = 'EPSG:3857';
                    }
                } catch (e) {}

                let features: Feature[] = [];
                if (content.type === 'FeatureCollection') features = format.readFeatures(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) as Feature[];
                else if (content.type === 'Feature') features = [format.readFeature(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) as Feature];
                else features = [new Feature({ geometry: format.readGeometry(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) })];

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);
                    mapInstance.current?.getView().fit(editSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
                    setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: `Đã nạp ${features.length} đối tượng.` });
                }
            } catch (err: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: `Lỗi đọc nội dung: ${err.message}` }); }
            finally { e.target.value = ''; }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { sodoto: 'BT-' + Date.now().toString().slice(-4), sothua: '0', geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: 'Dữ liệu đã được nạp vào hệ thống.' });
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans text-white">
            {/* TOOLBAR TRAY */}
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)"><Maximize size={20}/></button>
                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)"><Search size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền"><MapIcon size={20}/></button>
                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ"><Grid size={20}/></button>
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            {/* MAP AREA */}
            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />
                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
