                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
