                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? (
                                        <tr><td colSpan={4} className="p-12 text-center italic text-slate-600 uppercase text-[9px] font-bold tracking-widest">Chọn thửa đất để sửa</td></tr>
                                    ) : vertices.map((v, i) => {
                                        // Tính toán tọa độ hiển thị dựa trên hệ được chọn
                                        let dx, dy;
                                        if (coordSystem === 'VN2000') {
                                            const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:9210');
                                            dx = p[0]; dy = p[1];
                                        } else {
                                            const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:4326');
                                            dx = p[0]; dy = p[1];
                                        }

                                        return (
                                            <tr key={i} className="hover:bg-slate-900/50 transition-colors group">
                                                <td className="p-3 text-center text-slate-600 font-bold border-r border-slate-800">{i + 1}</td>
