                                                    <input 
                                                        type="text"
                                                        value={dx.toFixed(coordSystem === 'VN2000' ? 3 : 8)}
                                                        onChange={(e) => handleUpdateVertex(i, 'x', e.target.value)}
                                                        className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 outline-none text-blue-400 font-bold"
                                                    />
                                                </td>
                                                <td className="p-1 border-r border-slate-800">
                                                    <input 
                                                        type="text"
                                                        value={dy.toFixed(coordSystem === 'VN2000' ? 3 : 8)}
                                                        onChange={(e) => handleUpdateVertex(i, 'y', e.target.value)}
                                                        className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 outline-none text-emerald-400 font-bold"
                                                    />
                                                </td>
                                                <td className="p-1 text-center">
                                                    <button 
                                                        onClick={() => handleDeleteVertex(i)}
                                                        className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 p-2"
                                                    >
                                                        <Trash2 size={14}/>
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                        <div className="bg-blue-900/10 border border-blue-800/30 p-3 rounded-xl">
                            <p className="text-[9px] text-blue-400 italic leading-relaxed">
                                <Info size={10} className="inline mr-1 mb-0.5"/> 
                                Tip: Nhấn trực tiếp vào ô số để sửa tọa độ. Hệ VN-2000 (9210) sử dụng kinh tuyến trục 105.75 cho khu vực miền Nam.
                            </p>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
