import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation, Edit3, ClipboardList, Download, Settings2, FileDigit
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point, MultiPolygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000 (EPSG:9210 - Kinh tuyến trục 105.75 cho khu vực miền Nam)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);

    // Attributes
    const [soTo, setSoTo] = useState('');
    const [soThua, setSoThua] = useState('');

    // Vertices luôn lưu ở EPSG:3857 để đồng bộ với Map
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [coordSystem, setCoordSystem] = useState<'WGS84' | 'VN2000'>('VN2000');

    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            // Lọc bỏ điểm trùng cuối để quản lý bảng cho gọn
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const updateGeometryFromVertices = (newVertices: {x: number, y: number}[]) => {
        if (!selectedFeature) return;
        const coords = newVertices.map(v => [v.x, v.y]);
        if (coords.length >= 3) {
            // Đóng vùng (điểm cuối = điểm đầu)
            coords.push([...coords[0]]);
            const geom = selectedFeature.getGeometry();
            if (geom instanceof Polygon) {
                geom.setCoordinates([coords]);
            } else if (geom instanceof MultiPolygon) {
                geom.setCoordinates([[coords]]);
            }
            selectedFeature.changed();
        }
    };

    // --- CÁC HÀM XỬ LÝ BIÊN TẬP ĐỈNH ---

    const handleDeleteVertex = (index: number) => {
        if (vertices.length <= 3) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Vùng phải có ít nhất 3 đỉnh để hình thành đa giác.' });
            return;
        }
        const nextVertices = vertices.filter((_, i) => i !== index);
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleAddVertex = () => {
        if (vertices.length === 0) return;
        const last = vertices[vertices.length - 1];
        // Chèn 1 điểm mới lệch đi một chút so với điểm cuối
        const nextVertices = [...vertices, { x: last.x + 2, y: last.y + 2 }];
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleUpdateVertex = (index: number, axis: 'x' | 'y', value: string) => {
        const num = parseFloat(value);
        if (isNaN(num)) return;

        let finalX = vertices[index].x;
        let finalY = vertices[index].y;

        if (coordSystem === 'VN2000') {
            // Nếu đang sửa ở hệ VN2000, phải convert ngược về 3857 để Map hiểu
            const currentVn = proj.transform([vertices[index].x, vertices[index].y], 'EPSG:3857', 'EPSG:9210');
            const newVn = axis === 'x' ? [num, currentVn[1]] : [currentVn[0], num];
            const backToMap = proj.transform(newVn, 'EPSG:9210', 'EPSG:3857');
            finalX = backToMap[0];
            finalY = backToMap[1];
        } else {
            // Nếu đang sửa ở hệ WGS84
            const currentWgs = proj.transform([vertices[index].x, vertices[index].y], 'EPSG:3857', 'EPSG:4326');
            const newWgs = axis === 'x' ? [num, currentWgs[1]] : [currentWgs[0], num];
            const backToMap = proj.transform(newWgs, 'EPSG:4326', 'EPSG:3857');
            finalX = backToMap[0];
            finalY = backToMap[1];
        }

        const nextVertices = [...vertices];
        nextVertices[index] = { x: finalX, y: finalY };
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    // --- HÀM XUẤT TỌA ĐỘ ---

    const handleExportCoordsTxt = () => {
        if (vertices.length === 0) return;

        let content = `DANH SÁCH TỌA ĐỘ THỬA ĐẤT - HỆ: ${coordSystem}\n`;
        content += `STT\tX (m)\tY (m)\n`;
        content += `------------------------------------\n`;

        vertices.forEach((v, i) => {
            let displayX, displayY;
            if (coordSystem === 'VN2000') {
                const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:9210');
                displayX = p[0].toFixed(3);
                displayY = p[1].toFixed(3);
            } else {
                const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:4326');
                displayX = p[0].toFixed(8);
                displayY = p[1].toFixed(8);
            }
            content += `${i + 1}\t${displayX}\t${displayY}\n`;
        });

        // Điểm cuối trùng đầu cho khép góc
        const vFirst = vertices[0];
        let fx, fy;
        if (coordSystem === 'VN2000') {
            const p = proj.transform([vFirst.x, vFirst.y], 'EPSG:3857', 'EPSG:9210');
            fx = p[0].toFixed(3); fy = p[1].toFixed(3);
        } else {
            const p = proj.transform([vFirst.x, vFirst.y], 'EPSG:3857', 'EPSG:4326');
            fx = p[0].toFixed(8); fy = p[1].toFixed(8);
        }
        content += `${vertices.length + 1}\t${fx}\t${fy}\n`;

        const blob = new Blob([content], { type: 'text/plain' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = `ToaDo_VN2000_${Date.now()}.txt`;
        a.click();
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { 
                padding: [100, 100, 100, 100], 
                duration: 800,
                maxZoom: 20
            });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            // Mặc định Go to dùng VN2000 nếu số lớn
            let center;
            if (Math.abs(x) > 100000) {
                center = proj.transform([x, y], 'EPSG:9210', 'EPSG:3857');
            } else {
                center = proj.fromLonLat([x, y]);
            }
            mapInstance.current.getView().animate({
                center: center,
                zoom: 19,
                duration: 1000
            });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM();
        else source = new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature);
                updateVerticesFromFeature(e.feature);
                setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                const x = parseFloat(parts[0]);
                const y = parseFloat(parts[1]);
                // Tự động nhận diện VN2000 khi nhập tay
                if (x > 300000 && x < 900000) {
                    return proj.transform([x, y], 'EPSG:9210', 'EPSG:3857');
                }
                return proj.fromLonLat([x, y]);
            }).filter(Boolean) as [number, number][];

            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);

            const polygon = new Polygon([coords]);
            const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature);
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false);
            setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const getFirstCoordFromNested = (arr: any): [number, number] | null => {
        if (!Array.isArray(arr) || arr.length === 0) return null;
        if (typeof arr[0] === 'number' && typeof arr[1] === 'number') return [arr[0], arr[1]];
        return getFirstCoordFromNested(arr[0]);
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = (event.target?.result as string).trim();
                const content = JSON.parse(text);
                const format = new GeoJSON();
                let guessedDataProj = 'EPSG:4326';
                try {
                    let firstCoord: [number, number] | null = null;
                    if (content.type === 'FeatureCollection' && content.features?.[0]?.geometry?.coordinates) firstCoord = getFirstCoordFromNested(content.features[0].geometry.coordinates);
                    else if (content.type === 'Feature' && content.geometry?.coordinates) firstCoord = getFirstCoordFromNested(content.geometry.coordinates);
                    else if (content.coordinates) firstCoord = getFirstCoordFromNested(content.coordinates);
                    if (firstCoord) {
                        const [x, y] = firstCoord;
                        if (x > 300000 && x < 900000 && y > 1000000 && y < 2500000) guessedDataProj = 'EPSG:9210';
                        else if (Math.abs(x) > 2000000) guessedDataProj = 'EPSG:3857';
                    }
                } catch (e) {}

                let features: Feature[] = [];
                if (content.type === 'FeatureCollection') features = format.readFeatures(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) as Feature[];
                else if (content.type === 'Feature') features = [format.readFeature(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) as Feature];
                else features = [new Feature({ geometry: format.readGeometry(content, { dataProjection: guessedDataProj, featureProjection: 'EPSG:3857' }) })];

                if (features && features.length > 0) {
                    editSource.current.addFeatures(features);
                    const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature);
                    updateVerticesFromFeature(lastFeature);
                    mapInstance.current?.getView().fit(editSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
                    setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: `Đã nạp ${features.length} đối tượng.` });
                }
            } catch (err: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: `Lỗi đọc nội dung: ${err.message}` }); }
            finally { e.target.value = ''; }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;

        // Ràng buộc bắt buộc nhập Số tờ/Số thửa
        if (!soTo.trim() || !soThua.trim()) {
            setDialog({ 
                isOpen: true, 
                type: 'error', 
                title: 'Thiếu dữ liệu', 
                message: 'Vui lòng nhập đầy đủ Số tờ và Số thửa trước khi lưu vào Database.' 
            });
            return;
        }

        setLoading(true);
        try {
            const format = new GeoJSON();
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
            await parcelApi.create(targetTable, { 
                sodoto: soTo, 
                sothua: soThua, 
                geometry: geometry 
            });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: `Thửa đất ${soThua} - Tờ ${soTo} đã được lưu thành công.` });
            setSoTo('');
            setSoThua('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans text-white">
            {/* TOOLBAR TRAY */}
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)"><Maximize size={20}/></button>
                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)"><Search size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền"><MapIcon size={20}/></button>
                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ"><Grid size={20}/></button>
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            {/* MAP AREA */}
            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />
                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>
                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            {/* VERTEX EDITING PANEL */}
            <div className="w-[400px] bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a] flex items-center justify-between">
                    <div className="flex flex-col gap-1">
                        <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                            <ClipboardList size={16} className="text-blue-400"/> Biên tập tọa độ
                        </h3>
                        <div className="flex gap-2 mt-2">
                            <button 
                                onClick={() => setCoordSystem('VN2000')} 
                                className={`px-2 py-0.5 rounded text-[8px] font-black uppercase transition-all ${coordSystem === 'VN2000' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}
                            >VN-2000</button>
                            <button 
                                onClick={() => setCoordSystem('WGS84')} 
                                className={`px-2 py-0.5 rounded text-[8px] font-black uppercase transition-all ${coordSystem === 'WGS84' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}
                            >WGS-84</button>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={handleExportCoordsTxt} className="p-2.5 bg-indigo-600/10 text-indigo-400 hover:bg-indigo-600 hover:text-white rounded-xl transition-all shadow-lg" title="Xuất tọa độ TXT (VN2000/WGS84)"><Download size={16}/></button>
                        <button onClick={handleAddVertex} className="p-2.5 bg-emerald-600/10 text-emerald-400 hover:bg-emerald-600 hover:text-white rounded-xl transition-all shadow-lg" title="Thêm đỉnh mới"><Plus size={18}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    {/* ATTRIBUTES SECTION */}
                    <div className="space-y-4 bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
                        <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2"><FileDigit size={12}/> Thông tin định danh</h4>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-1.5">
                                <label className="text-[9px] font-black text-gray-500 uppercase ml-1">Số tờ *</label>
                                <input 
                                    className="w-full bg-slate-950 border border-slate-700 rounded-xl px-3 py-2.5 text-xs text-white outline-none focus:border-blue-500 font-black tracking-widest"
                                    placeholder="..."
                                    value={soTo}
                                    onChange={e => setSoTo(e.target.value)}
                                />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-[9px] font-black text-gray-500 uppercase ml-1">Số thửa *</label>
                                <input 
                                    className="w-full bg-slate-950 border border-slate-700 rounded-xl px-3 py-2.5 text-xs text-white outline-none focus:border-blue-500 font-black tracking-widest"
                                    placeholder="..."
                                    value={soThua}
                                    onChange={e => setSoThua(e.target.value)}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Lớp đích PostGIS</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button 
                            onClick={handleSaveToDB} 
                            disabled={loading || !selectedFeature || !soTo.trim() || !soThua.trim()} 
                            className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30 disabled:cursor-not-allowed shadow-xl shadow-blue-900/20"
                        >
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE
                        </button>
                        {(!soTo.trim() || !soThua.trim()) && selectedFeature && (
                            <p className="text-[9px] text-orange-400 italic text-center animate-pulse">Cần nhập Số tờ/Số thửa để lưu</p>
                        )}
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách tọa độ ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as any)).toLocaleString()} m²</span>}
                        </div>

                        <div className="bg-slate-950 rounded-2xl border border-slate-800 overflow-hidden">
                            <table className="w-full text-[10px] font-mono border-collapse">
                                <thead className="bg-slate-900 text-slate-500">
                                    <tr>
                                        <th className="p-3 text-center w-10 border-b border-slate-800">#</th>
                                        <th className="p-3 text-left border-b border-slate-800">{coordSystem === 'VN2000' ? 'X (VN2k)' : 'Kinh độ'}</th>
                                        <th className="p-3 text-left border-b border-slate-800">{coordSystem === 'VN2000' ? 'Y (VN2k)' : 'Vĩ độ'}</th>
                                        <th className="p-3 text-center w-10 border-b border-slate-800"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? (
                                        <tr><td colSpan={4} className="p-12 text-center italic text-slate-600 uppercase text-[9px] font-bold tracking-widest">Chọn thửa đất để sửa</td></tr>
                                    ) : vertices.map((v, i) => {
                                        // Tính toán tọa độ hiển thị dựa trên hệ được chọn
                                        let dx, dy;
                                        if (coordSystem === 'VN2000') {
                                            const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:9210');
                                            dx = p[0]; dy = p[1];
                                        } else {
                                            const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:4326');
                                            dx = p[0]; dy = p[1];
                                        }

                                        return (
                                            <tr key={i} className="hover:bg-slate-900/50 transition-colors group">
                                                <td className="p-3 text-center text-slate-600 font-bold border-r border-slate-800">{i + 1}</td>
                                                <td className="p-1 border-r border-slate-800">
                                                    <input 
                                                        type="text"
                                                        value={dx.toFixed(coordSystem === 'VN2000' ? 3 : 8)}
                                                        onChange={(e) => handleUpdateVertex(i, 'x', e.target.value)}
                                                        className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 outline-none text-blue-400 font-bold"
                                                    />
                                                </td>
                                                <td className="p-1 border-r border-slate-800">
                                                    <input 
                                                        type="text"
                                                        value={dy.toFixed(coordSystem === 'VN2000' ? 3 : 8)}
                                                        onChange={(e) => handleUpdateVertex(i, 'y', e.target.value)}
                                                        className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 outline-none text-emerald-400 font-bold"
                                                    />
                                                </td>
                                                <td className="p-1 text-center">
                                                    <button 
                                                        onClick={() => handleDeleteVertex(i)}
                                                        className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 p-2"
                                                    >
                                                        <Trash2 size={14}/>
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                        <div className="bg-blue-900/10 border border-blue-800/30 p-3 rounded-xl">
                            <p className="text-[9px] text-blue-400 italic leading-relaxed">
                                <Info size={10} className="inline mr-1 mb-0.5"/> 
                                Tip: Nhấn trực tiếp vào ô số để sửa tọa độ. Hệ VN-2000 (9210) sử dụng kinh tuyến trục 105.75 cho khu vực miền Nam.
                            </p>
                        </div>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="grid grid-cols-2 gap-3">
                        <label className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 cursor-pointer transition-all group">
                            <FileUp size={20} className="text-slate-500 group-hover:text-blue-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Import</span>
                            <input type="file" className="hidden" accept=".geojson,.json,.txt,.csv" onChange={handleFileUpload} />
                        </label>
                        <button onClick={() => {
                            const features = editSource.current.getFeatures();
                            const json = new GeoJSON().writeFeatures(features, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
                            const blob = new Blob([json], { type: 'application/json' });
                            const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `GeoMaster_${Date.now()}.geojson`; a.click();
                        }} disabled={editSource.current.getFeatures().length === 0} className="flex flex-col items-center justify-center p-4 bg-slate-800/30 hover:bg-slate-800 rounded-2xl border border-slate-800 transition-all group disabled:opacity-30">
                            <FileDown size={20} className="text-slate-500 group-hover:text-orange-400 mb-2" />
                            <span className="text-[9px] font-black uppercase text-slate-500 group-hover:text-white">Export GeoJSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* MODALS */}
            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><Navigation size={20} className="text-blue-500"/> Di chuyển đến điểm</h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">X (VN2000) hoặc Kinh độ</label>
                                <input className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all" value={searchCoords.x} onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Y (VN2000) hoặc Vĩ độ</label>
                                <input className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all" value={searchCoords.y} onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}/>
                            </div>
                            <button onClick={handleGoToCoordinate} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95">DI CHUYỂN NGAY</button>
                        </div>
                    </div>
                </div>
            )}

            {isManualModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter">Nhập tọa độ thủ công</h3>
                            <button onClick={() => setIsManualModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <p className="text-[10px] text-gray-400 italic">Hỗ trợ dán tọa độ VN-2000 hoặc WGS84 trực tiếp (Ngăn cách bởi dấu phẩy, khoảng trắng hoặc Tab).</p>
                            <textarea value={manualCoords} onChange={e => setManualCoords(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-6 text-sm font-mono text-blue-400 focus:border-blue-500 outline-none h-64 shadow-inner resize-none" placeholder="597937.797, 1229843.202&#10;597937.58, 1229813.203..." />
                            <button onClick={() => handleProcessManualInput(manualCoords)} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all">DỰNG HÌNH</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, BasemapConfig } from '../types';
import { gisService } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { 
    MousePointer2, Plus, Trash2, Save, FileDown, FileUp, 
    RefreshCw, Magnet, List, Hash, CheckCircle2, AlertTriangle, 
    Grid, Keyboard, X, Info, Move, Map as MapIcon, 
    Search, Maximize, MapPin, Navigation, Edit3, ClipboardList, Download, Settings2, FileDigit
} from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Graticule } from 'ol/layer';
import { OSM, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Polygon, Point, MultiPolygon } from 'ol/geom';
import Feature from 'ol/Feature';
import { Draw, Modify, Snap, Select } from 'ol/interaction';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Register VN-2000 (EPSG:9210 - Kinh tuyến trục 105.75 cho khu vực miền Nam)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const EditorPage: React.FC<{ user: User | null }> = ({ user }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const editSource = useRef<VectorSource>(new VectorSource());

    // States
    const [activeInteraction, setActiveInteraction] = useState<'SELECT' | 'DRAW' | 'MODIFY'>('SELECT');
    const [isSnapping, setIsSnapping] = useState(true);
    const [showBasemap, setShowBasemap] = useState(true);
    const [showGrid, setShowGrid] = useState(true);
    const [selectedFeature, setSelectedFeature] = useState<Feature | null>(null);

    // Attributes
    const [soTo, setSoTo] = useState('');
    const [soThua, setSoThua] = useState('');

    // Vertices luôn lưu ở EPSG:3857 để đồng bộ với Map
    const [vertices, setVertices] = useState<{x: number, y: number}[]>([]);
    const [coordSystem, setCoordSystem] = useState<'WGS84' | 'VN2000'>('VN2000');

    const [targetTable, setTargetTable] = useState('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState('');

    // Modal States
    const [isManualModalOpen, setIsManualModalOpen] = useState(false);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [searchCoords, setSearchCoords] = useState({ x: '', y: '' });
    const [manualCoords, setManualCoords] = useState('');
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Layers Refs
    const baseLayerRef = useRef<TileLayer<any>>(new TileLayer({ zIndex: 0 }));

    const gridLayerRef = useRef<Graticule>(new Graticule({
        strokeStyle: new style.Stroke({ 
            color: 'rgba(255, 255, 255, 0.1)', 
            width: 1,
            lineDash: [4, 4] 
        }),
        showLabels: false, 
        wrapX: false,
        zIndex: 5
    }));

    const getEditStyle = (feature: Feature) => {
        const styles = [
            new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
            })
        ];

        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            coords.slice(0, -1).forEach((coord, index) => {
                styles.push(new style.Style({
                    geometry: new Point(coord),
                    image: new style.Circle({
                        radius: 4,
                        fill: new style.Fill({ color: '#fff' }),
                        stroke: new style.Stroke({ color: '#3b82f6', width: 2 })
                    }),
                    text: new style.Text({
                        text: (index + 1).toString(),
                        font: 'bold 10px sans-serif',
                        fill: new style.Fill({ color: '#94a3b8' }),
                        offsetX: 10,
                        offsetY: -10,
                        textAlign: 'left'
                    })
                }));
            });
        }
        return styles;
    };

    const initMap = async () => {
        if (!mapElement.current) return;
        const [tables, maps] = await Promise.all([
            gisService.getSpatialTables().catch(() => []),
            gisService.getBasemaps().catch(() => [])
        ]);
        setSpatialTables(tables);
        if (tables.length > 0) setTargetTable(tables[0].table_name);
        setBasemaps(maps);
        const defMap = maps.find(m => m.isDefault) || maps[0];
        if (defMap) setActiveBasemapId(defMap.id);

        const map = new Map({
            target: mapElement.current,
            layers: [
                baseLayerRef.current,
                gridLayerRef.current,
                new VectorLayer({ 
                    source: editSource.current, 
                    style: (feature) => getEditStyle(feature as Feature), 
                    zIndex: 100 
                })
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 18 }),
            controls: []
        });

        const select = new Select({ 
            style: (feature) => {
                const baseStyles = getEditStyle(feature as Feature);
                baseStyles[0].getStroke()?.setColor('#f97316');
                baseStyles[0].getStroke()?.setWidth(3);
                baseStyles[0].getStroke()?.setLineDash([5, 5]);
                return baseStyles;
            }
        });
        map.addInteraction(select);
        select.on('select', (e) => {
            const feature = e.selected[0] || null;
            setSelectedFeature(feature);
            updateVerticesFromFeature(feature);
        });

        mapInstance.current = map;
    };

    const updateVerticesFromFeature = (feature: Feature | null) => {
        if (!feature) { setVertices([]); return; }
        const geom = feature.getGeometry();
        let coords: any[] = [];
        if (geom instanceof Polygon) {
            coords = geom.getCoordinates()[0];
        } else if (geom instanceof MultiPolygon) {
            const polyCoords = geom.getCoordinates();
            if (polyCoords.length > 0 && polyCoords[0].length > 0) {
                coords = polyCoords[0][0];
            }
        }

        if (coords.length > 0) {
            const displayCoords = coords.slice(0, -1);
            setVertices(displayCoords.map(c => ({ x: c[0], y: c[1] })));
        }
    };

    const updateGeometryFromVertices = (newVertices: {x: number, y: number}[]) => {
        if (!selectedFeature) return;
        const coords = newVertices.map(v => [v.x, v.y]);
        if (coords.length >= 3) {
            coords.push([...coords[0]]);
            const geom = selectedFeature.getGeometry();
            if (geom instanceof Polygon) {
                geom.setCoordinates([coords]);
            } else if (geom instanceof MultiPolygon) {
                geom.setCoordinates([[coords]]);
            }
            selectedFeature.changed();
        }
    };

    const handleDeleteVertex = (index: number) => {
        if (vertices.length <= 3) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Vùng phải có ít nhất 3 đỉnh để hình thành đa giác.' });
            return;
        }
        const nextVertices = vertices.filter((_, i) => i !== index);
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleAddVertex = () => {
        if (vertices.length === 0) return;
        const last = vertices[vertices.length - 1];
        const nextVertices = [...vertices, { x: last.x + 2, y: last.y + 2 }];
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleUpdateVertex = (index: number, axis: 'x' | 'y', value: string) => {
        const num = parseFloat(value);
        if (isNaN(num)) return;

        let finalX = vertices[index].x;
        let finalY = vertices[index].y;

        if (coordSystem === 'VN2000') {
            const currentVn = proj.transform([vertices[index].x, vertices[index].y], 'EPSG:3857', 'EPSG:9210');
            const newVn = axis === 'x' ? [num, currentVn[1]] : [currentVn[0], num];
            const backToMap = proj.transform(newVn, 'EPSG:9210', 'EPSG:3857');
            finalX = backToMap[0];
            finalY = backToMap[1];
        } else {
            const currentWgs = proj.transform([vertices[index].x, vertices[index].y], 'EPSG:3857', 'EPSG:4326');
            const newWgs = axis === 'x' ? [num, currentWgs[1]] : [currentWgs[0], num];
            const backToMap = proj.transform(newWgs, 'EPSG:4326', 'EPSG:3857');
            finalX = backToMap[0];
            finalY = backToMap[1];
        }

        const nextVertices = [...vertices];
        nextVertices[index] = { x: finalX, y: finalY };
        setVertices(nextVertices);
        updateGeometryFromVertices(nextVertices);
    };

    const handleExportCoordsTxt = () => {
        if (vertices.length === 0) return;
        let content = `DANH SÁCH TỌA ĐỘ THỬA ĐẤT - HỆ: ${coordSystem}\nSTT\tX (m)\tY (m)\n------------------------------------\n`;
        vertices.forEach((v, i) => {
            let displayX, displayY;
            if (coordSystem === 'VN2000') {
                const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:9210');
                displayX = p[0].toFixed(3); displayY = p[1].toFixed(3);
            } else {
                const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:4326');
                displayX = p[0].toFixed(8); displayY = p[1].toFixed(8);
            }
            content += `${i + 1}\t${displayX}\t${displayY}\n`;
        });
        const vFirst = vertices[0];
        let fx, fy;
        if (coordSystem === 'VN2000') {
            const p = proj.transform([vFirst.x, vFirst.y], 'EPSG:3857', 'EPSG:9210');
            fx = p[0].toFixed(3); fy = p[1].toFixed(3);
        } else {
            const p = proj.transform([vFirst.x, vFirst.y], 'EPSG:3857', 'EPSG:4326');
            fx = p[0].toFixed(8); fy = p[1].toFixed(8);
        }
        content += `${vertices.length + 1}\t${fx}\t${fy}\n`;
        const blob = new Blob([content], { type: 'text/plain' });
        const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `ToaDo_VN2000_${Date.now()}.txt`; a.click();
    };

    const handleFitView = () => {
        if (!mapInstance.current || !editSource.current) return;
        const extent = editSource.current.getExtent();
        if (!isExtentEmpty(extent)) {
            mapInstance.current.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 800, maxZoom: 20 });
        } else {
            setDialog({ isOpen: true, type: 'info', title: 'Thông báo', message: 'Chưa có hình vẽ nào để thu phóng.' });
        }
    };

    const handleGoToCoordinate = () => {
        const x = parseFloat(searchCoords.x);
        const y = parseFloat(searchCoords.y);
        if (isNaN(x) || isNaN(y)) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Tọa độ nhập vào không hợp lệ.' });
            return;
        }
        if (mapInstance.current) {
            let center = Math.abs(x) > 100000 ? proj.transform([x, y], 'EPSG:9210', 'EPSG:3857') : proj.fromLonLat([x, y]);
            mapInstance.current.getView().animate({ center: center, zoom: 19, duration: 1000 });
            setIsSearchModalOpen(false);
        }
    };

    useEffect(() => {
        initMap();
        return () => mapInstance.current?.setTarget(undefined);
    }, []);

    useEffect(() => {
        if (baseLayerRef.current) baseLayerRef.current.setVisible(showBasemap);
        if (gridLayerRef.current) gridLayerRef.current.setVisible(showGrid);
    }, [showBasemap, showGrid]);

    useEffect(() => {
        if (!mapInstance.current || !activeBasemapId) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source = config.type === 'OSM' ? new OSM() : new XYZ({ url: config.url.replace(/\{z\}/g, '{z}').replace(/\{x\}/g, '{x}').replace(/\{y\}/g, '{y}'), crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;
        const interactions = map.getInteractions();
        interactions.getArray().filter(i => i instanceof Draw || i instanceof Modify || i instanceof Snap).forEach(i => map.removeInteraction(i));

        if (activeInteraction === 'DRAW') {
            const draw = new Draw({ source: editSource.current, type: 'Polygon' });
            map.addInteraction(draw);
            draw.on('drawend', (e) => {
                setSelectedFeature(e.feature); updateVerticesFromFeature(e.feature); setActiveInteraction('SELECT');
            });
        }
        if (activeInteraction === 'MODIFY') {
            const modify = new Modify({ source: editSource.current });
            map.addInteraction(modify);
            modify.on('modifyend', (e) => {
                const feature = e.features.getArray()[0];
                if (feature) updateVerticesFromFeature(feature);
            });
        }
        if (isSnapping) map.addInteraction(new Snap({ source: editSource.current }));
    }, [activeInteraction, isSnapping]);

    const handleProcessManualInput = (inputText: string) => {
        try {
            const lines = inputText.trim().split(/[\n;]+/);
            const coords = lines.map(line => {
                const parts = line.split(/[,\s\t]+/).filter(Boolean);
                if (parts.length < 2) return null;
                const x = parseFloat(parts[0]); const y = parseFloat(parts[1]);
                return (x > 300000 && x < 900000) ? proj.transform([x, y], 'EPSG:9210', 'EPSG:3857') : proj.fromLonLat([x, y]);
            }).filter(Boolean) as [number, number][];
            if (coords.length < 3) throw new Error("Cần ít nhất 3 điểm.");
            if (coords[0][0] !== coords[coords.length-1][0] || coords[0][1] !== coords[coords.length-1][1]) coords.push([...coords[0]] as [number, number]);
            const polygon = new Polygon([coords]); const feature = new Feature({ geometry: polygon });
            editSource.current.addFeature(feature); setSelectedFeature(feature); updateVerticesFromFeature(feature);
            mapInstance.current?.getView().fit(polygon.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
            setIsManualModalOpen(false); setManualCoords('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file) return;
        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const text = (event.target?.result as string).trim(); const content = JSON.parse(text); const format = new GeoJSON();
                let features = format.readFeatures(content, { featureProjection: 'EPSG:3857' }) as Feature[];
                if (features && features.length > 0) {
                    editSource.current.addFeatures(features); const lastFeature = features[features.length - 1];
                    setSelectedFeature(lastFeature); updateVerticesFromFeature(lastFeature);
                    mapInstance.current?.getView().fit(editSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 800 });
                }
            } catch (err: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: `Lỗi đọc nội dung: ${err.message}` }); }
            finally { e.target.value = ''; }
        };
        reader.readAsText(file);
    };

    const handleSaveToDB = async () => {
        if (!targetTable || !selectedFeature) return;
        if (!soTo.trim() || !soThua.trim()) {
            setDialog({ isOpen: true, type: 'error', title: 'Thiếu dữ liệu', message: 'Vui lòng nhập đầy đủ Số tờ và Số thửa trước khi lưu vào Database.' });
            return;
        }

        setLoading(true);
        try {
            const format = new GeoJSON();
            // LƯU Ý: Chuyển đổi sang EPSG:9210 (VN-2000) trước khi gửi lên Backend
            const geometry = format.writeGeometryObject(selectedFeature.getGeometry()!, { 
                dataProjection: 'EPSG:9210', 
                featureProjection: 'EPSG:3857' 
            });
            await parcelApi.create(targetTable, { sodoto: soTo, sothua: soThua, geometry: geometry });
            setDialog({ isOpen: true, type: 'success', title: 'Đã lưu', message: `Thửa đất ${soThua} - Tờ ${soTo} đã được lưu thành công vào hệ tọa độ VN-2000.` });
            setSoTo(''); setSoThua('');
        } catch (e: any) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: e.message }); }
        finally { setLoading(false); }
    };

    return (
        <div className="flex h-full w-full bg-[#05070a] overflow-hidden font-sans text-white">
            <div className="w-16 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-3 z-20 shadow-2xl">
                <button onClick={() => setActiveInteraction('SELECT')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'SELECT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chọn đối tượng (V)"><MousePointer2 size={20}/></button>
                <button onClick={() => setActiveInteraction('DRAW')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'DRAW' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Vẽ vùng mới (P)"><Plus size={20}/></button>
                <button onClick={() => setActiveInteraction('MODIFY')} className={`p-3 rounded-xl transition-all ${activeInteraction === 'MODIFY' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Chỉnh sửa đỉnh (M)"><Move size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={handleFitView} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-emerald-400" title="Xem toàn bộ hình vẽ (Fit View)"><Maximize size={20}/></button>
                <button onClick={() => setIsSearchModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Tìm tọa độ (Go to)"><Search size={20}/></button>
                <div className="w-8 h-px bg-slate-800 my-2" />
                <button onClick={() => setShowBasemap(!showBasemap)} className={`p-3 rounded-xl transition-all ${showBasemap ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Bản đồ nền"><MapIcon size={20}/></button>
                <button onClick={() => setShowGrid(!showGrid)} className={`p-3 rounded-xl transition-all ${showGrid ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Bật/Tắt Lưới tọa độ"><Grid size={20}/></button>
                <button onClick={() => setIsManualModalOpen(true)} className="p-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-blue-400" title="Nhập tọa độ tay"><Keyboard size={20}/></button>
                <button onClick={() => setIsSnapping(!isSnapping)} className={`p-3 rounded-xl transition-all ${isSnapping ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30' : 'text-slate-500 hover:bg-slate-800'}`} title="Chế độ bắt điểm (Snap)"><Magnet size={20}/></button>
                <button onClick={() => { editSource.current.clear(); setSelectedFeature(null); setVertices([]); }} className="p-3 rounded-xl text-slate-500 hover:bg-red-600/20 hover:text-red-500 mt-auto" title="Xóa toàn bộ"><Trash2 size={20}/></button>
            </div>

            <div className="flex-1 relative bg-[#05070a]">
                <div ref={mapElement} className="w-full h-full" />
                <div className="absolute top-6 left-6 z-10 flex flex-col gap-2">
                    {showBasemap && (
                        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 p-1.5 rounded-xl shadow-2xl flex flex-col gap-1">
                            {basemaps.map(bm => (
                                <button key={bm.id} onClick={() => setActiveBasemapId(bm.id)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeBasemapId === bm.id ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>{bm.name}</button>
                            ))}
                        </div>
                    )}
                </div>
                <div className="absolute bottom-6 left-6 z-10">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700 px-4 py-2 rounded-2xl shadow-2xl flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full animate-pulse ${activeInteraction !== 'SELECT' ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-600'}`}></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">Mode: {activeInteraction}</span>
                    </div>
                </div>
            </div>

            <div className="w-[400px] bg-[#0d1117] border-l border-slate-800 flex flex-col z-20 shadow-2xl">
                <div className="p-6 border-b border-slate-800 bg-[#05070a] flex items-center justify-between">
                    <div className="flex flex-col gap-1">
                        <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                            <ClipboardList size={16} className="text-blue-400"/> Biên tập tọa độ
                        </h3>
                        <div className="flex gap-2 mt-2">
                            <button onClick={() => setCoordSystem('VN2000')} className={`px-2 py-0.5 rounded text-[8px] font-black uppercase transition-all ${coordSystem === 'VN2000' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>VN-2000</button>
                            <button onClick={() => setCoordSystem('WGS84')} className={`px-2 py-0.5 rounded text-[8px] font-black uppercase transition-all ${coordSystem === 'WGS84' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>WGS-84</button>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={handleExportCoordsTxt} className="p-2.5 bg-indigo-600/10 text-indigo-400 hover:bg-indigo-600 hover:text-white rounded-xl transition-all shadow-lg" title="Xuất tọa độ TXT"><Download size={16}/></button>
                        <button onClick={handleAddVertex} className="p-2.5 bg-emerald-600/10 text-emerald-400 hover:bg-emerald-600 hover:text-white rounded-xl transition-all shadow-lg" title="Thêm đỉnh mới"><Plus size={18}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    <div className="space-y-4 bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
                        <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2"><FileDigit size={12}/> Thông tin định danh</h4>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-1.5">
                                <label className="text-[9px] font-black text-gray-500 uppercase ml-1">Số tờ *</label>
                                <input className="w-full bg-slate-950 border border-slate-700 rounded-xl px-3 py-2.5 text-xs text-white outline-none focus:border-blue-500 font-black tracking-widest" placeholder="..." value={soTo} onChange={e => setSoTo(e.target.value)}/>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-[9px] font-black text-gray-500 uppercase ml-1">Số thửa *</label>
                                <input className="w-full bg-slate-950 border border-slate-700 rounded-xl px-3 py-2.5 text-xs text-white outline-none focus:border-blue-500 font-black tracking-widest" placeholder="..." value={soThua} onChange={e => setSoThua(e.target.value)}/>
                            </div>
                        </div>
                    </div>

                    <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Lớp đích PostGIS</label>
                        <select className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-xs font-bold text-white outline-none" value={targetTable} onChange={e => setTargetTable(e.target.value)}>
                            {spatialTables.map(t => <option key={t.table_name} value={t.table_name}>{t.display_name || t.table_name}</option>)}
                        </select>
                        <button onClick={handleSaveToDB} disabled={loading || !selectedFeature || !soTo.trim() || !soThua.trim()} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-30 shadow-xl shadow-blue-900/20">
                            {loading ? <RefreshCw className="animate-spin" size={14}/> : <Save size={14}/>} LƯU VÀO DATABASE (VN-2000)
                        </button>
                    </div>

                    <div className="h-px bg-slate-800" />

                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Hash size={12}/> Danh sách tọa độ ({vertices.length})</h4>
                            {selectedFeature && <span className="text-[9px] font-black text-emerald-500 bg-emerald-950/30 px-2 py-0.5 rounded border border-emerald-800/50">{Math.round(getArea(selectedFeature.getGeometry() as any)).toLocaleString()} m²</span>}
                        </div>

                        <div className="bg-slate-950 rounded-2xl border border-slate-800 overflow-hidden">
                            <table className="w-full text-[10px] font-mono border-collapse">
                                <thead className="bg-slate-900 text-slate-500">
                                    <tr>
                                        <th className="p-3 text-center w-10 border-b border-slate-800">#</th>
                                        <th className="p-3 text-left border-b border-slate-800">{coordSystem === 'VN2000' ? 'X (VN2k)' : 'Kinh độ'}</th>
                                        <th className="p-3 text-left border-b border-slate-800">{coordSystem === 'VN2000' ? 'Y (VN2k)' : 'Vĩ độ'}</th>
                                        <th className="p-3 text-center w-10 border-b border-slate-800"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-800 text-slate-400">
                                    {vertices.length === 0 ? (
                                        <tr><td colSpan={4} className="p-12 text-center italic text-slate-600 uppercase text-[9px] font-bold tracking-widest">Chọn thửa đất để sửa</td></tr>
                                    ) : vertices.map((v, i) => {
                                        let dx, dy;
                                        if (coordSystem === 'VN2000') {
                                            const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:9210');
                                            dx = p[0]; dy = p[1];
                                        } else {
                                            const p = proj.transform([v.x, v.y], 'EPSG:3857', 'EPSG:4326');
                                            dx = p[0]; dy = p[1];
                                        }
                                        return (
                                            <tr key={i} className="hover:bg-slate-900/50 transition-colors group">
                                                <td className="p-3 text-center text-slate-600 font-bold border-r border-slate-800">{i + 1}</td>
                                                <td className="p-1 border-r border-slate-800">
                                                    <input type="text" value={dx.toFixed(coordSystem === 'VN2000' ? 3 : 8)} onChange={(e) => handleUpdateVertex(i, 'x', e.target.value)} className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 outline-none text-blue-400 font-bold"/>
                                                </td>
                                                <td className="p-1 border-r border-slate-800">
                                                    <input type="text" value={dy.toFixed(coordSystem === 'VN2000' ? 3 : 8)} onChange={(e) => handleUpdateVertex(i, 'y', e.target.value)} className="w-full bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 outline-none text-emerald-400 font-bold"/>
                                                </td>
                                                <td className="p-1 text-center">
                                                    <button onClick={() => handleDeleteVertex(i)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 p-2"><Trash2 size={14}/></button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>

            {/* MODALS & DIALOGS */}
            {isSearchModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/95 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2rem] w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                            <h3 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><Navigation size={20} className="text-blue-500"/> Di chuyển điểm</h3>
                            <button onClick={() => setIsSearchModalOpen(false)} className="text-gray-500 hover:text-white transition-all"><X size={24}/></button>
                        </div>
                        <div className="space-y-5">
                            <div className="space-y-2"><label className="text-[10px] text-gray-500 uppercase tracking-widest ml-1">X (VN2000) / Kinh độ</label><input className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500" value={searchCoords.x} onChange={e => setSearchCoords({...searchCoords, x: e.target.value})}/></div>
                            <div className="space-y-2"><label className="text-[10px] text-gray-500 uppercase tracking-widest ml-1">Y (VN2000) / Vĩ độ</label><input className="w-full bg-slate-950 border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500" value={searchCoords.y} onChange={e => setSearchCoords({...searchCoords, y: e.target.value})}/></div>
                            <button onClick={handleGoToCoordinate} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest">DI CHUYỂN</button>
                        </div>
                    </div>
                </div>
            )}

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-sm border border-gray-800 shadow-2xl p-8 text-center flex flex-col items-center">
                        {dialog.type === 'success' ? <CheckCircle2 size={40} className="text-emerald-500 mb-4"/> : <AlertTriangle size={40} className="text-red-500 mb-4"/>}
                        <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">Đã hiểu</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default EditorPage;

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

// Bộ nhớ đệm cho cấu trúc bảng (Schema Cache)
const SCHEMA_CACHE = new Map();

export default function(pool, logSystemAction) {
    const router = express.Router();

    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    const resolveTableColumns = async (tableName) => {
        if (SCHEMA_CACHE.has(tableName)) return SCHEMA_CACHE.get(tableName);
        try {
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const dbColsMap = {}; res.rows.forEach(r => dbColsMap[r.column_name.toLowerCase()] = r.column_name);
            const mapping = {};
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey;
                for (const candidate of candidates) { if (dbColsMap[candidate]) { foundCol = dbColsMap[candidate]; break; } }
                mapping[standardKey] = foundCol;
            }
            SCHEMA_CACHE.set(tableName, mapping); return mapping;
        } catch (e) { return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich' }; }
    };

    const syncTableSchema = async (tableName) => {
        try {
            SCHEMA_CACHE.delete(tableName);
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "sodoto" TEXT`);
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "sothua" TEXT`);
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "loaidat" TEXT`);
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "dientich" NUMERIC`);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
        } catch (e) { console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message); }
    };

    router.get('/spatial-tables', async (req, res) => {
        try { const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`); res.json(result.rows); }
        catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            // MẶC ĐỊNH SỬ DỤNG SRID 9210 CHO BẢNG MỚI
            await pool.query(`CREATE TABLE IF NOT EXISTS "${safeName}" (gid SERIAL PRIMARY KEY, sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC, geometry GEOMETRY(Geometry, 9210), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)`);
            await pool.query(`INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3) ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name`, [safeName, displayName, description]);
            await syncTableSchema(safeName); await logSystemAction(req, 'CREATE_TABLE', `Tạo bảng mới VN2k: ${safeName}`);
            await pool.query('COMMIT'); res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params; const { sodoto, sothua, tenchu, diachi } = req.query;
        try {
            const cols = await resolveTableColumns(table);
            // TRẢ VỀ DỮ LIỆU ĐÃ CHUYỂN SANG 4326 ĐỂ OPENLAYERS HIỂN THỊ DỄ DÀNG (HOẶC GIỮ NGUYÊN TÙY MAP)
            let query = `SELECT gid, "${cols.sodoto}" as sodoto, "${cols.sothua}" as sothua, "${cols.tenchu}" as tenchu, "${cols.diachi}" as diachi, "${cols.loaidat}" as loaidat, "${cols.dientich}" as dientich, ST_AsGeoJSON(geometry) as geometry FROM "${table}" WHERE 1=1`;
            const params = []; let idx = 1;
            if (sodoto) { query += ` AND "${cols.sodoto}"::text ILIKE $${idx++}`; params.push(`%${sodoto}%`); }
            if (sothua) { query += ` AND "${cols.sothua}"::text ILIKE $${idx++}`; params.push(`%${sothua}%`); }
            const result = await pool.query(query + ` ORDER BY gid DESC LIMIT 100`, params);
            res.json(result.rows.map(row => ({ ...row, geometry: row.geometry ? JSON.parse(row.geometry) : null })));
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params; const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            // LƯU Ý QUAN TRỌNG: SỬ DỤNG SRID 9210 TRONG SQL
            let geomSql = geometry ? `ST_SetSRID(ST_GeomFromGeoJSON($7), 9210)` : 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) params.push(JSON.stringify(geometry));
            const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid`;
            const result = await pool.query(query, params);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params; const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich]; let idx = 7;
            if (geometry) { query += `, geometry=ST_SetSRID(ST_GeomFromGeoJSON($${idx}), 9210)`; params.push(JSON.stringify(geometry)); idx++; }
            await pool.query(query + ` WHERE gid=$${idx}`, [...params, gid]); res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try { await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]); res.json({ status: 'ok' }); }
        catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

// Bộ nhớ đệm cho cấu trúc bảng (Schema Cache)
const SCHEMA_CACHE = new Map();

export default function(pool, logSystemAction) {
    const router = express.Router();

    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    const resolveTableColumns = async (tableName) => {
        if (SCHEMA_CACHE.has(tableName)) return SCHEMA_CACHE.get(tableName);
        try {
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const dbColsMap = {}; res.rows.forEach(r => dbColsMap[r.column_name.toLowerCase()] = r.column_name);
            const mapping = {};
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey;
                for (const candidate of candidates) { if (dbColsMap[candidate]) { foundCol = dbColsMap[candidate]; break; } }
                mapping[standardKey] = foundCol;
            }
            SCHEMA_CACHE.set(tableName, mapping); return mapping;
        } catch (e) { return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich' }; }
    };

    const syncTableSchema = async (tableName) => {
        try {
            SCHEMA_CACHE.delete(tableName);
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "sodoto" TEXT`);
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "sothua" TEXT`);
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "loaidat" TEXT`);
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "dientich" NUMERIC`);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
        } catch (e) { console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message); }
    };

    router.get('/spatial-tables', async (req, res) => {
        try { const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`); res.json(result.rows); }
        catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            // SỬ DỤNG SRID 9210 (VN-2000)
            await pool.query(`CREATE TABLE IF NOT EXISTS "${safeName}" (gid SERIAL PRIMARY KEY, sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC, geometry GEOMETRY(Geometry, 9210), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)`);
            await pool.query(`INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3) ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name`, [safeName, displayName, description]);
            await syncTableSchema(safeName); await logSystemAction(req, 'CREATE_TABLE', `Tạo bảng VN2k: ${safeName}`);
            await pool.query('COMMIT'); res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params; const { sodoto, sothua, tenchu, diachi } = req.query;
        try {
            const cols = await resolveTableColumns(table);
            // ST_AsGeoJSON tự động lấy geometry thô từ DB (đang là 9210)
            let query = `SELECT gid, "${cols.sodoto}" as sodoto, "${cols.sothua}" as sothua, "${cols.tenchu}" as tenchu, "${cols.diachi}" as diachi, "${cols.loaidat}" as loaidat, "${cols.dientich}" as dientich, ST_AsGeoJSON(geometry) as geometry FROM "${table}" WHERE 1=1`;
            const params = []; let idx = 1;
            if (sodoto) { query += ` AND "${cols.sodoto}"::text ILIKE $${idx++}`; params.push(`%${sodoto}%`); }
            if (sothua) { query += ` AND "${cols.sothua}"::text ILIKE $${idx++}`; params.push(`%${sothua}%`); }
            const result = await pool.query(query + ` ORDER BY gid DESC LIMIT 100`, params);
            res.json(result.rows.map(row => ({ ...row, geometry: row.geometry ? JSON.parse(row.geometry) : null })));
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params; const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            // SỬ DỤNG SRID 9210
            let geomSql = geometry ? `ST_SetSRID(ST_GeomFromGeoJSON($7), 9210)` : 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) params.push(JSON.stringify(geometry));
            const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid`;
            const result = await pool.query(query, params);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params; const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich]; let idx = 7;
            // SỬ DỤNG SRID 9210
            if (geometry) { query += `, geometry=ST_SetSRID(ST_GeomFromGeoJSON($${idx}), 9210)`; params.push(JSON.stringify(geometry)); idx++; }
            await pool.query(query + ` WHERE gid=$${idx}`, [...params, gid]); res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 
        if (!file) return res.status(400).json({ error: 'No file uploaded' });
        try {
            const cols = await resolveTableColumns(table);
            const buffer = fs.readFileSync(file.path);
            let geojson;
            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());
            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;
            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");

            // SỬ DỤNG SRID 9210 KHI CẬP NHẬT QUA FILE
            if (gid) {
                await pool.query(`UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_SetSRID(ST_GeomFromGeoJSON($7), 9210) WHERE gid=$8`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]);
            } else {
                await pool.query(`INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_SetSRID(ST_GeomFromGeoJSON($7), 9210))`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]);
            }
            fs.unlinkSync(file.path);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: e.message });
        }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try { await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]); res.json({ status: 'ok' }); }
        catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}
